ensure(data, "fault_auto_restart_enabled");
ensure(data, "over_temperature_restart_enabled");
ensure(data, "supports_qpigs2");
ensure(data, "_day_key");

// -------------------------------------------------
// 2) ENERGIES
// -------------------------------------------------
ensure(data, "load_energy_month_kwh");
ensure(data, "load_energy_year_kwh");
ensure(data, "load_energy_day_kwh");
ensure(data, "load_energy_total_kwh");

ensure(data, "pv_energy_month_kwh");
ensure(data, "pv_energy_year_kwh");
ensure(data, "pv_energy_day_kwh");
ensure(data, "pv_energy_total_kwh");

ensure(data, "battery_charge_month_kwh");
ensure(data, "battery_charge_year_kwh");
ensure(data, "battery_discharge_month_kwh");
ensure(data, "battery_discharge_year_kwh");
ensure(data, "grid_energy_month_kwh");
ensure(data, "grid_energy_year_kwh");

// -------------------------------------------------
// 2b) PREMIUM NEW
// -------------------------------------------------
ensure(data, "grid_to_load_today");
ensure(data, "solar_supply_today_pct");
ensure(data, "battery_supply_today_pct");
ensure(data, "grid_supply_today_pct");
ensure(data, "energy_flow_calc_quality", "unknown");

ensure(data, "battery_health_score");
ensure(data, "battery_health_state", "unknown");
ensure(data, "battery_health_reason", "unknown");
ensure(data, "battery_stress_state", "unknown");

ensure(data, "inverter_health_score");
ensure(data, "inverter_health_state", "unknown");
ensure(data, "inverter_stress_state", "unknown");

// -------------------------------------------------
// 3) DIAG
// -------------------------------------------------
if (!data.diag || typeof data.diag !== "object") data.diag = {};

ensure(data.diag, "model", "unknown");
ensure(data.diag, "serial", "unknown");
ensure(data.diag, "fw_main", "unknown");
ensure(data.diag, "fw_remote", "unknown");

ensure(data.diag, "fault_state", "unknown");
