ensure(data.diag, "premium_voltage_sag");
ensure(data.diag, "premium_rest_voltage_avg");
ensure(data.diag, "premium_load_voltage_avg");
ensure(data.diag, "premium_battery_low_voltage_events_today");
ensure(data.diag, "premium_battery_near_low_voltage_minutes_today");
ensure(data.diag, "premium_battery_high_crate_minutes_today");
ensure(data.diag, "premium_battery_very_high_crate_minutes_today");
ensure(data.diag, "premium_battery_high_relative_power_minutes_today");
ensure(data.diag, "premium_battery_very_high_relative_power_minutes_today");
ensure(data.diag, "premium_battery_stress_mode", "unknown");
ensure(data.diag, "premium_battery_c_rate");
ensure(data.diag, "premium_battery_relative_power_ratio");
ensure(data.diag, "premium_inverter_high_temp_minutes_today");
ensure(data.diag, "premium_inverter_fault_minutes_today");

// raw / debug
ensure(data.diag, "raw_command", "");
ensure(data.diag, "raw_response", "");
ensure(data.diag, "raw_response_hex", "");
ensure(data.diag, "_last_raw_command_ts", 0);
ensure(data.diag, "_last_raw_response_ts", 0);
ensure(data.diag, "_last_raw_response_hex_ts", 0);

// -------------------------------------------------
// 3b) RAW UNIQUEMENT SI COMMANDE MANUELLE EN ATTENTE
// -------------------------------------------------
let rawPending = flow.get(rawPendingKey);
if (!rawPending || typeof rawPending !== "object") rawPending = { active: false };

const pendingAge = Date.now() - Number(rawPending.ts || 0);

if (rawPending.active === true && pendingAge > 15000) {
  rawPending = { active: false };
  flow.set(rawPendingKey, rawPending);
}

const rawCommand = cleanString(
  msg._raw_command ??
  msg.raw_command ??
  msg.payload?._raw_command ??
  msg.payload?.raw_command ??
  ""
);

const rawResponse = cleanString(
  msg._raw_response ??
  msg.raw_response ??
  msg.payload?._raw_response ??
  msg.payload?.raw_response ??
  msg.payload?.raw ??
  ""
);

const rawResponseHex = cleanString(
  msg._raw_response_hex ??
  msg.raw_response_hex ??
  msg.payload?._raw_response_hex ??
  msg.payload?.raw_response_hex ??
  ""
);

const pendingCommand = cleanString(rawPending.command || "");

if (msg._raw_manual === true) {
  data.diag.raw_command = rawCommand || pendingCommand || "";
  data.diag._last_raw_command_ts = Date.now();

  rawPending = {
    active: true,
    command: rawCommand || pendingCommand || "",
    ts: Date.now()
  };
  flow.set(rawPendingKey, rawPending);
}
else if (
  rawPending.active === true &&
  (rawResponse || rawResponseHex) &&
  pendingCommand &&
  rawCommand &&
  rawCommand === pendingCommand
) {
  data.diag.raw_command = pendingCommand;
  data.diag._last_raw_command_ts = Number(rawPending.ts || Date.now());

  if (rawResponse) {
    data.diag.raw_response = rawResponse;
    data.diag._last_raw_response_ts = Date.now();
  }

  if (rawResponseHex) {
    data.diag.raw_response_hex = rawResponseHex;
    data.diag._last_raw_response_hex_ts = Date.now();
  }

  rawPending = { active: false };
  flow.set(rawPendingKey, rawPending);
}

// -------------------------------------------------
// 3c) SUPPORT COMMANDES
// -------------------------------------------------
if (!data.diag.command_support || typeof data.diag.command_support !== "object") {
  data.diag.command_support = {};
}

function ensureCmdSupport(obj, key) {
  if (!obj[key] || typeof obj[key] !== "object") obj[key] = {};
  ensure(obj[key], "disabled", false);
  ensure(obj[key], "nak_count", 0);
  ensure(obj[key], "last_ok", 0);
  ensure(obj[key], "last_nak", 0);
  ensure(obj[key], "retry_after", 0);
}

ensureCmdSupport(data.diag.command_support, "qpigs2");
ensureCmdSupport(data.diag.command_support, "qet");
ensureCmdSupport(data.diag.command_support, "qey");
ensureCmdSupport(data.diag.command_support, "qem");
ensureCmdSupport(data.diag.command_support, "qed");
ensureCmdSupport(data.diag.command_support, "qlt");
ensureCmdSupport(data.diag.command_support, "qly");
ensureCmdSupport(data.diag.command_support, "qlm");
ensureCmdSupport(data.diag.command_support, "qld");

// -------------------------------------------------
// 4) PARAMS
// -------------------------------------------------
if (!data.params || typeof data.params !== "object") data.params = {};
if (!data.params.qpiri || typeof data.params.qpiri !== "object") data.params.qpiri = {};
if (!data.params.qdop || typeof data.params.qdop !== "object") data.params.qdop = {};

const qpiri = data.params.qpiri;
const qdop = data.params.qdop;

ensure(qpiri, "battery_type");
ensure(qpiri, "battery_type_code");

ensure(qpiri, "output_source_priority");
ensure(qpiri, "output_source_priority_code");

ensure(qpiri, "charger_source_priority");
ensure(qpiri, "charger_source_priority_code");

ensure(qpiri, "battery_bulk_voltage");
ensure(qpiri, "battery_float_voltage");
ensure(qpiri, "battery_re_discharge_voltage");
ensure(qpiri, "battery_recharge_voltage");
ensure(qpiri, "battery_under_voltage");

// IMPORTANT:
// on ne force plus ces 2 clés si absentes,
// pour éviter de republier une valeur vide/invalide
if (qpiri.max_ac_charging_current === undefined) {
  delete qpiri.max_ac_charging_current;
}
if (qpiri.max_charging_current === undefined) {
  delete qpiri.max_charging_current;
}

ensure(qpiri, "max_discharging_current");
ensure(qpiri, "ts", 0);

ensure(qdop, "battery_recharge_capacity_pct");
ensure(qdop, "battery_redischarge_capacity_pct");
ensure(qdop, "battery_under_capacity_pct");
ensure(qdop, "ts", 0);

// -------------------------------------------------
// 4b) NETTOYAGE SELECTS MQTT
// supprime les champs invalides avant publication
// -------------------------------------------------
pruneInvalidSelectState(data);

// -------------------------------------------------
// 4c) NETTOYAGE GLOBAL JSON
// -------------------------------------------------
sanitizeForJson(data);

// -------------------------------------------------
// 5) SAVE LAST STATE
// -------------------------------------------------
flow.set(stateKey, data);

// -------------------------------------------------
// 6) PUBLISH MQTT
// -------------------------------------------------
return [
  {
    topic: `voltronic/${inv}/state`,
    payload: JSON.stringify(data),
    retain: true
  },
  {
    topic: `voltronic/${inv}/availability`,
    payload: "online",
    retain: true
  }
];

const inv = msg.inverterNum ?? 1;

const qKey = `inv${inv}_queue`;
const inFlightKey = `inv${inv}_inflight`;

let q = flow.get(qKey);
if (!Array.isArray(q)) q = [];

const inFlight = flow.get(inFlightKey);
const now = Date.now();

// -------------------------------------------------
// Helpers
// -------------------------------------------------
function getQpigs2State() {
    const qpKey = `inv${inv}_qpigs2_state`;
    let st = flow.get(qpKey);

    if (!st || typeof st !== "object") {
        st = {
            fail_count: 0,
            disabled: false,
            last_try: 0,
            last_ok: 0,
            last_fail: 0,
            reason: ""
        };
        flow.set(qpKey, st);
    }

    return st;
}

function asArray(input) {
    if (Array.isArray(input)) return input;
    if (Array.isArray(input?.payload) && input.payload?.[0]?.command) return input.payload;
    return [input];
}

function cleanStr(v) {
    return String(v ?? "").trim();
}

function normalizeCmd(m) {
    if (!m || typeof m !== "object") return null;

    const rawCommand = cleanStr(m._raw_command || m.command || m._cmd || m.payload);
    const cmd = rawCommand.toUpperCase();

    if (!cmd) return null;

    const origin = cleanStr(m._origin);
    const explicitPriority = m._priority === true;

    const isPriority =
        explicitPriority ||
        origin === "ha_set" ||
        origin === "learn_retry" ||
        origin === "poll_fast_fault" ||
        origin === "poll_fault_trigger";

    return {
        inverterNum: m.inverterNum ?? inv,
        command: cmd,
        _cmd: cmd,
        _raw_command: rawCommand || cmd,
        payload: cmd,

        _origin: origin,
        _burst: m._burst === true,
        _learn: m._learn || null,
        _qpigs2_probe: m._qpigs2_probe === true,
        _raw_manual: m._raw_manual === true,
        _priority: explicitPriority,

        // debug / suivi
        enqueued_ts: now,
        priority: isPriority
    };
}

function getDedupeKey(item) {
    return String(item.command || "").trim().toUpperCase();
}

// -------------------------------------------------
// Prépare la liste à ajouter
// -------------------------------------------------
const incoming = asArray(msg);
const toPush = [];

for (const m of incoming) {
    const item = normalizeCmd(m);
    if (!item) continue;
    toPush.push(item);
}

// -------------------------------------------------
// Ajout dans la queue
// -------------------------------------------------
let added = 0;
let dropped = 0;

for (const item of toPush) {
    const cmd = item.command;
    const dedupeKey = getDedupeKey(item);

    // ---------------------------------------------
    // Règle spéciale QPIGS2
    // ---------------------------------------------
    if (cmd === "QPIGS2") {
        const st = getQpigs2State();

        if (st.disabled && item._qpigs2_probe !== true) {
            dropped++;
            continue;
        }
    }

    // ---------------------------------------------
    // Anti-doublon queue
    // ---------------------------------------------
    const alreadyQueued = q.some(x => {
        if (!x) return false;
        return getDedupeKey(x) === dedupeKey;
    });

    // ---------------------------------------------
    // Anti-doublon inflight
    // ---------------------------------------------
    const alreadyInFlight =
        inFlight &&
        String(inFlight.cmd || "").trim().toUpperCase() === dedupeKey;

    // ---------------------------------------------
    // Règles priorité
    // - priorité = passe devant
    // - mais pas en doublon strict
    // ---------------------------------------------
    const isLearnRetry = item._origin === "learn_retry";

    if (!isLearnRetry && (alreadyQueued || alreadyInFlight)) {
        dropped++;
        continue;
    }

    if (item.priority) {
        q.unshift(item);
    } else {
        q.push(item);
    }

    added++;
}

// -------------------------------------------------
// Limite de taille
// - on garde le début de queue (priorités déjà devant)
// -------------------------------------------------
if (q.length > 200) {
    q = q.slice(0, 200);
}

flow.set(qKey, q);

const head = q[0];
const headTxt = head
    ? `${head.command}${head.priority ? " !" : ""}`
    : "empty";

node.status({
    fill: "blue",
    shape: "dot",
    text: `q:${q.length} +${added}${dropped ? ` -${dropped}` : ""} [${headTxt}]`
});

// déclenche le pump
return {
    inverterNum: inv,
    topic: "pump"
};

const inv = msg.inverterNum ?? 1;

const qKey = `inv${inv}_queue`;
const inFlightKey = `inv${inv}_inflight`;
const pendingLearnKey = `learn_pending_inv${inv}`;

// -------------------------------------------------
// Helpers QPIGS2
// -------------------------------------------------
function getQpigs2State() {
    const key = `inv${inv}_qpigs2_state`;
    let st = flow.get(key);

    if (!st || typeof st !== "object") {
        st = {
            fail_count: 0,
            disabled: false,
            last_try: 0,
            last_ok: 0,
            last_fail: 0,
            reason: ""
        };
        flow.set(key, st);
    }

    return st;
}

function setQpigs2State(st) {
    flow.set(`inv${inv}_qpigs2_state`, st);
}

function markQpigs2Fail(reason) {
    const st = getQpigs2State();
    st.fail_count = Number(st.fail_count || 0) + 1;
    st.last_fail = Date.now();
    st.reason = reason || "timeout";

    if (st.fail_count >= 3) {
        st.disabled = true;
    }

    setQpigs2State(st);
    return st;
}

// -------------------------------------------------
// Helpers généraux
// -------------------------------------------------
function cleanStr(v) {
    return String(v ?? "").trim();
}

function getTimeoutMs(cmd, origin) {
    if (origin === "ha_set" || origin === "learn_retry") return 4000;
    if (cmd === "QPIRI" || cmd === "QDOP") return 4000;
    return 3000;
}

function normalizeOut(item) {
    const rawCommand = cleanStr(item?._raw_command || item?.command || item?._cmd || item?.payload);
    const cmd = rawCommand.toUpperCase();

    if (!cmd) return null;

    return {
        ...item,
        inverterNum: item?.inverterNum ?? inv,
        command: cmd,
        _cmd: cmd,
        _raw_command: rawCommand || cmd,
        payload: cmd
    };
}

// -------------------------------------------------
// 0) Gère l'inflight courant
// -------------------------------------------------
let inFlight = flow.get(inFlightKey);
let timeoutEvent = null;

if (inFlight) {
    const now = Date.now();
    const age = now - Number(inFlight.ts || 0);
    const timeoutMs = Number(inFlight.timeoutMs || 3000);

    if (age < timeoutMs) {
        return [null, null];
    }

    const timedOutCmd = cleanStr(inFlight.cmd).toUpperCase();
    const timedOutRaw = cleanStr(inFlight.raw || timedOutCmd);
    const timedOutOrigin = cleanStr(inFlight.origin);

    if (timedOutCmd === "QPIGS2") {
        const st = markQpigs2Fail("timeout");

        node.status({
            fill: st.disabled ? "red" : "yellow",
            shape: st.disabled ? "ring" : "dot",
            text: st.disabled
                ? `QPIGS2 timeout disable (${st.fail_count}/3)`
                : `QPIGS2 timeout (${st.fail_count}/3)`
        });
    }

    const pendingLearn = flow.get(pendingLearnKey);

    if (
        pendingLearn &&
        String(pendingLearn.cmd || "").trim().toUpperCase() === timedOutCmd
    ) {
        timeoutEvent = {
            inverterNum: inv,
            topic: "learn_timeout",
            payload: {
                inverter: inv,
                command: timedOutCmd,
                raw_command: timedOutRaw,
                raw_response: null,
                timeout: true,
                nak: false,
                raw: null,
                fields: [],
                nums: [],
                value: null
            },
            _cmd: timedOutCmd,
            command: timedOutCmd,
            _raw_command: timedOutRaw,
            _learn_timeout: true,
            _origin: timedOutOrigin || "timeout"
        };

        flow.set(pendingLearnKey, null);

        node.status({
            fill: "red",
            shape: "ring",
            text: `LEARN TIMEOUT ${pendingLearn.param || timedOutCmd}`
        });
    }

    flow.set(inFlightKey, null);
    inFlight = null;
}

// -------------------------------------------------
// 1) Lit la queue
// -------------------------------------------------
let q = flow.get(qKey);
if (!Array.isArray(q) || q.length === 0) {
    return [null, timeoutEvent];
}

q = q.filter(x => x && (x.command || x._cmd || x.payload));
if (q.length === 0) {
    flow.set(qKey, []);
    return [null, timeoutEvent];
}

// -------------------------------------------------
// 2) Dépile la prochaine commande
// -------------------------------------------------
const next = q.shift();
flow.set(qKey, q);

const out = normalizeOut(next);
if (!out) {
    return [{
        inverterNum: inv,
        topic: "pump"
    }, timeoutEvent];
}

const cmd = out.command;
const origin = cleanStr(out._origin);
const timeoutMs = getTimeoutMs(cmd, origin);
const isPriority = out.priority === true || out._priority === true;

// -------------------------------------------------
// 3) Marque inflight
// -------------------------------------------------
flow.set(inFlightKey, {
    cmd,
    raw: out._raw_command || cmd,
    ts: Date.now(),
    timeoutMs,

    inverterNum: inv,
    origin: origin,
    learn: out._learn || null,
    raw_manual: out._raw_manual === true,
    enqueued_ts: out.enqueued_ts || null,
    priority: isPriority
});

// -------------------------------------------------
// 4) Statut visuel
// -------------------------------------------------
let fill = "green";
if (origin === "ha_set" || origin === "learn_retry") fill = "yellow";
if (origin === "poll_fast_fault" || origin === "poll_fault_trigger" || isPriority) fill = "red";

const shortOrigin = origin || "poll";
const prioTxt = isPriority ? " !" : "";

node.status({
    fill,
    shape: "dot",
    text: `${cmd}${prioTxt} [${shortOrigin}] (${q.length} left)`
});

// -------------------------------------------------
// 5) Envoi au node "construire commande"
// -------------------------------------------------
return [out, timeoutEvent];

// HA SET -> Voltronic CMD
// 2 sorties:
//   1) paramètres gérés par apprentissage
//   2) commandes directes vers Queue Enqueue
//
// topic: voltronic/<inv>/set/<param>
// payload: valeur

const m = String(msg.topic || "").match(/^voltronic\/(\d+)\/set\/(.+)$/);
if (!m) return null;

const inverterNum = Number(m[1]);
const param = String(m[2] || "").trim();

if (!Number.isFinite(inverterNum) || !param) return null;

// -------------------------------------------------
// Normalisation payload
// -------------------------------------------------
function cleanString(v) {
  let s = String(v ?? "").trim();
  if (!s) return "";

  s = s.replace(/^"+|"+$/g, "");

  try {
    if (
      s.startsWith('\\"') ||
      (s.startsWith('"') && s.endsWith('"'))
    ) {
      const parsed = JSON.parse(s);
      if (typeof parsed === "string") s = parsed;
    }
  } catch (e) {
    // ignore
  }

  return String(s ?? "").trim().replace(/^"+|"+$/g, "");
}

let v = msg.payload;
if (typeof v === "string") {
  v = cleanString(v);
}

// -------------------------------------------------
// Helpers
// -------------------------------------------------
const toNum = (x) => {
  if (x == null) return null;

  if (typeof x === "string") {
    const s = cleanString(x);
    const m = s.match(/-?\d+(\.\d+)?/);
    if (!m) return null;
    x = m[0];
  }

  const n = Number(x);
  return Number.isFinite(n) ? n : null;
};

const clamp = (x, a, b) => Math.min(b, Math.max(a, Number(x)));
const pad3 = (x) => String(Math.trunc(Number(x))).padStart(3, "0");

const mk = (c, extra = {}) => ({
  inverterNum,
  command: c,
  _cmd: c,
  payload: c,
  _burst: true,
  _origin: extra._origin || "ha_set",
  ...extra
});

function getParallelId(inv) {
  let machine = flow.get(`inv${inv}_parallel_id`);
  if (machine === undefined || machine === null || machine === "") machine = 0;
  machine = Number(machine);
  if (!Number.isFinite(machine) || machine < 0 || machine > 9) machine = 0;
  return machine;
}

function normKey(v) {
  return cleanString(v)
    .toLowerCase()
    .replace(/\s+/g, "")
    .replace(/\+/g, "plus");
}

function isTwoChoiceOutputPriorityEnabled(inv) {
  return global.get(`inverter_${inv}.output_priority_2choices`) === true;
}

function parseBoolLike(v) {
  if (typeof v === "boolean") return v;
  if (typeof v === "number") return v !== 0;

  const s = normKey(v);

  if (["1", "on", "true", "enable", "enabled"].includes(s)) return true;
  if (["0", "off", "false", "disable", "disabled"].includes(s)) return false;

  return null;
}

// -------------------------------------------------
// Plages tensions selon système batterie
// -------------------------------------------------
function getBatterySystemVoltage() {
  const sysV = Number(
    global.get("config.batterySystemVoltage") ||
    global.get("battery_system_voltage") ||
    48
  );
  return sysV === 24 ? 24 : 48;
}

function getVoltageRanges() {
  const sysV = getBatterySystemVoltage();

  if (sysV === 24) {
    return {
      battery_bulk_voltage: { min: 24, max: 30, decimals: 1 },
      battery_float_voltage: { min: 24, max: 30, decimals: 1 },
      battery_recharge_voltage: { min: 22, max: 25.5, decimals: 1 },
      battery_re_discharge_voltage: { min: 24, max: 29, decimals: 1 },
      battery_under_voltage: { min: 20, max: 27, decimals: 1 }
    };
  }

  return {
    battery_bulk_voltage: { min: 40, max: 65, decimals: 1 },
    battery_float_voltage: { min: 40, max: 65, decimals: 1 },
    battery_recharge_voltage: { min: 40, max: 65, decimals: 1 },
    battery_re_discharge_voltage: { min: 40, max: 65, decimals: 1 },
    battery_under_voltage: { min: 40, max: 65, decimals: 1 }
  };
}

function validateVoltageParam(paramName, rawValue) {
  const ranges = getVoltageRanges();
  const rule = ranges[paramName];
  if (!rule) {
    return { ok: false, value: null, reason: "unknown_param" };
  }

  const n = toNum(rawValue);
  if (n == null) {
    return { ok: false, value: null, reason: "not_a_number", rule };
  }

  if (n < rule.min || n > rule.max) {
    return { ok: false, value: n, reason: "out_of_range", rule };
  }

  const factor = 10 ** (rule.decimals || 1);
  const rounded = Math.round(n * factor) / factor;

  return { ok: true, value: rounded, rule };
}

function rejectInvalidVoltage(paramName, rawValue) {
  const res = validateVoltageParam(paramName, rawValue);
  if (res.ok) return res;

  const txt = res.rule
    ? `${paramName} out of range (${res.rule.min}-${res.rule.max}V)`
    : `${paramName} invalid`;

  node.status({
    fill: "red",
    shape: "ring",
    text: txt
  });

  return null;
}

// -------------------------------------------------
// Paramètres apprenables
// -------------------------------------------------
function canonLearnParam(p) {
  const s = cleanString(p);

  const map = {
    battery_bulk_voltage: "battery_bulk_voltage",
    battery_float_voltage: "battery_float_voltage",

    battery_cutoff_voltage: "battery_under_voltage",
    battery_under_voltage: "battery_under_voltage",

    back_to_grid_voltage: "battery_recharge_voltage",
    battery_recharge_voltage: "battery_recharge_voltage",

    back_to_battery_voltage: "battery_re_discharge_voltage",
    battery_re_discharge_voltage: "battery_re_discharge_voltage",

    max_charging_current: "max_charging_current",

    grid_charging_current: "max_ac_charging_current",
    max_ac_charging_current: "max_ac_charging_current",

    charger_source_priority: "charger_source_priority",
    output_source_priority: "output_source_priority"
  };

  return map[s] || s;
}

function isLearnableParam(p) {
  const lp = canonLearnParam(p);
  return [
    "battery_bulk_voltage",
    "battery_float_voltage",
    "battery_under_voltage",
    "battery_recharge_voltage",
    "battery_re_discharge_voltage",
    "max_charging_current",
    "max_ac_charging_current",
    "charger_source_priority",
    "output_source_priority"
  ].includes(lp);
}

// -------------------------------------------------
// OUTPUT SOURCE PRIORITY
// -------------------------------------------------
function getForcedTwoChoiceOutputCommand(v) {
  const raw = cleanString(v);
  const key = normKey(v);

  if (raw === "0" || key === "0") return "POP00";
  if (raw === "1" || key === "1") return "POP01";

  const map = {
    sub: "POP00",
    solarutilitybat: "POP00",

    sbu: "POP01",
    solarbatutility: "POP01",

    usb: null,
    utilitysolarbat: null
  };

  return Object.prototype.hasOwnProperty.call(map, key) ? map[key] : null;
}

function getOutputPrioritySlotNormal(v) {
  const raw = cleanString(v);
  const key = normKey(v);

  if (raw === "0" || key === "0") return 0;
  if (raw === "1" || key === "1") return 1;
  if (raw === "2" || key === "2") return 2;

  const map = {
    utilitysolarbat: 0,
    usb: 0,

    solarutilitybat: 1,
    sub: 1,

    solarbatutility: 2,
    sbu: 2
  };

  return Number.isInteger(map[key]) ? map[key] : null;
}

// -------------------------------------------------
// CHARGER SOURCE PRIORITY
// -------------------------------------------------
function getChargerPrioritySlot(v) {
  const raw = cleanString(v);
  const key = normKey(v);

  if (raw === "0" || key === "0") return 0;
  if (raw === "1" || key === "1") return 1;
  if (raw === "2" || key === "2") return 2;

  const map = {
    solarfirst: 0,
    cso: 0,

    solarplusutility: 1,
    solarutility: 1,
    snu: 1,

    onlysolar: 2,
    oso: 2
  };

  return Number.isInteger(map[key]) ? map[key] : null;
}

// -------------------------------------------------
// RAW COMMAND MANUELLE
// -------------------------------------------------
if (param === "raw_command") {
  const cmd = cleanString(v);
  if (!cmd) return null;

  flow.set(`inv${inverterNum}_raw_pending`, {
    active: true,
    command: cmd,
    ts: Date.now()
  });

  const rawMsg = mk(cmd, {
    _burst: false,
    _origin: "ha_set",
    _raw_manual: true,
    _raw_command: cmd,
    _ha_param: "raw_command",
    _ha_value: v
  });

  node.status({
    fill: "yellow",
    shape: "dot",
    text: `RAW ${cmd}`
  });

  return [null, [rawMsg]];
}

// -------------------------------------------------
// OUTPUT SOURCE PRIORITY EN MODE 2 CHOIX FORCE
// -------------------------------------------------
if (param === "output_source_priority" && isTwoChoiceOutputPriorityEnabled(inverterNum)) {
  const cmd = getForcedTwoChoiceOutputCommand(v);

  if (!cmd) {
    node.status({
      fill: "red",
      shape: "ring",
      text: "output priority unsupported"
    });
    return null;
  }

  const setMsg = mk(cmd, {
    _burst: false,
    _origin: "ha_set",
    _ha_param: param,
    _ha_value: v
  });

  const refreshMsgs = ["QPIRI", "QMOD", "QPIGS"].map(c => mk(c, {
    _origin: "ha_refresh",
    _from_param: param
  }));

  const out = [setMsg, ...refreshMsgs];

  node.status({
    fill: "green",
    shape: "dot",
    text: `SET ${param} (${cmd}) forced 2-choice`
  });

  return [null, out];
}

// -------------------------------------------------
// PARAMÈTRES APPRENABLES
// -------------------------------------------------
if (isLearnableParam(param)) {
  const learnParam = canonLearnParam(param);

  let learnValue = v;
  let learnMode = "number";

  // validation tensions avant apprentissage
  if ([
    "battery_bulk_voltage",
    "battery_float_voltage",
    "battery_under_voltage",
    "battery_recharge_voltage",
    "battery_re_discharge_voltage"
  ].includes(learnParam)) {
    const valid = rejectInvalidVoltage(learnParam, v);
    if (!valid) return null;
    learnValue = valid.value;
    learnMode = "number";
  }

  if (learnParam === "output_source_priority") {
    const slot = getOutputPrioritySlotNormal(v);

    if (slot == null) {
      node.status({
        fill: "red",
        shape: "ring",
        text: "output priority unsupported"
      });
      return null;
    }

    learnValue = slot;
    learnMode = "enum_profile";
  }

  if (learnParam === "charger_source_priority") {
    const slot = getChargerPrioritySlot(v);

    if (slot == null) {
      node.status({
        fill: "red",
        shape: "ring",
        text: "charger priority unsupported"
      });
      return null;
    }

    learnValue = slot;
    learnMode = "enum_profile";
  }

  const learnMsg = {
    inverterNum,
    topic: msg.topic,
    payload: learnValue,
    _origin: "ha_set",
    _ha_param: learnParam,
    _ha_param_raw: param,
    _ha_value: learnValue,
    _ha_value_raw: v,
    _learn_mode: learnMode
  };

  node.status({
    fill: "blue",
    shape: "dot",
    text: `LEARN ${learnParam}`
  });

  return [learnMsg, null];
}

// -------------------------------------------------
// Tables de mapping direct (hors apprentissage)
// -------------------------------------------------
const batteryTypeMap = {
  AGM: "PBT00",
  Flooded: "PBT01",
  User: "PBT02",
  Pylon: "PBT03",
  Weco: "PBT05",
  Soltaro: "PBT06",
  Lib: "PBT08",
  Lic: "PBT09"
};

// -------------------------------------------------
// Résolution commande directe
// -------------------------------------------------
const machine = getParallelId(inverterNum);

let cmd = null;
let refresh = ["QMOD", "QPIGS"];

// ----- switchs flags QFLAG -----
if (param === "overload_bypass") {
  const b = parseBoolLike(v);
  if (b == null) return null;

  cmd = b ? "PEb" : "PDb";
  refresh = ["QFLAG", "QMOD", "QPIGS"];

} else if (param === "fault_auto_restart") {
  const b = parseBoolLike(v);
  if (b == null) return null;

  cmd = b ? "PEu" : "PDu";
  refresh = ["QFLAG", "QMOD", "QPIGS"];

} else if (param === "over_temperature_restart") {
  const b = parseBoolLike(v);
  if (b == null) return null;

  cmd = b ? "PEv" : "PDv";
  refresh = ["QFLAG", "QMOD", "QPIGS"];

} else if (param === "battery_type") {
  const sv = cleanString(v);
  cmd = batteryTypeMap[sv] || null;
  refresh = ["QPIRI", "QMOD", "QPIGS"];

} else if (param === "max_discharging_current") {
  const sv = cleanString(v);
  if (sv === "0") return null;

  const nv = toNum(sv);
  if (nv == null) return null;

  cmd = `PBATMAXDISC${pad3(clamp(nv, 1, 200))}`;
  refresh = ["QPIRI", "QPIGS"];

} else if (param === "battery_recharge_capacity_pct") {
  const nv = toNum(v);
  if (nv == null) return null;
  cmd = `PBCC${pad3(clamp(nv, 5, 95))}`;
  refresh = ["QDOP", "QPIGS"];

} else if (param === "battery_redischarge_capacity_pct") {
  const nv = toNum(v);
  if (nv == null) return null;
  cmd = `PBDC${pad3(clamp(nv, 10, 100))}`;
  refresh = ["QDOP", "QPIGS"];

} else if (param === "battery_under_capacity_pct") {
  const nv = toNum(v);
  if (nv == null) return null;
  cmd = `PSDC${pad3(clamp(nv, 0, 90))}`;
  refresh = ["QDOP", "QPIGS"];
}

if (!cmd) return null;

// -------------------------------------------------
// Construction sortie directe
// -------------------------------------------------
const setMsg = mk(cmd, {
  _burst: false,
  _origin: "ha_set",
  _ha_param: param,
  _ha_value: v
});

const refreshMsgs = refresh.map(c => mk(c, {
  _origin: "ha_refresh",
  _from_param: param
}));

const out = [setMsg, ...refreshMsgs];

node.status({
  fill: "green",
  shape: "dot",
  text: `SET ${param} (${cmd}) + refresh x${refreshMsgs.length}`
});

return [null, out];

// HA SET -> Voltronic CMD
// 2 sorties:
//   1) paramètres gérés par apprentissage
//   2) commandes directes vers Queue Enqueue
//
// topic: voltronic/<inv>/set/<param>
// payload: valeur

const m = String(msg.topic || "").match(/^voltronic\/(\d+)\/set\/(.+)$/);
if (!m) return null;

const inverterNum = Number(m[1]);
const param = String(m[2] || "").trim();

if (!Number.isFinite(inverterNum) || !param) return null;

// -------------------------------------------------
// Normalisation payload
// -------------------------------------------------
function cleanString(v) {
