// -------------------------------------------------
// 3b) RAW UNIQUEMENT SI COMMANDE MANUELLE EN ATTENTE
// -------------------------------------------------
let rawPending = flow.get(rawPendingKey);
if (!rawPending || typeof rawPending !== "object") rawPending = { active: false };

const pendingAge = Date.now() - Number(rawPending.ts || 0);

if (rawPending.active === true && pendingAge > 15000) {
  rawPending = { active: false };
  flow.set(rawPendingKey, rawPending);
}

const rawCommand = cleanString(
  msg._raw_command ??
  msg.raw_command ??
  msg.payload?._raw_command ??
  msg.payload?.raw_command ??
  ""
);

const rawResponse = cleanString(
  msg._raw_response ??
  msg.raw_response ??
  msg.payload?._raw_response ??
  msg.payload?.raw_response ??
  msg.payload?.raw ??
  ""
);

const rawResponseHex = cleanString(
  msg._raw_response_hex ??
  msg.raw_response_hex ??
  msg.payload?._raw_response_hex ??
  msg.payload?.raw_response_hex ??
  ""
);

const pendingCommand = cleanString(rawPending.command || "");

if (msg._raw_manual === true) {
  data.diag.raw_command = rawCommand || pendingCommand || "";
  data.diag._last_raw_command_ts = Date.now();

  rawPending = {
    active: true,
    command: rawCommand || pendingCommand || "",
    ts: Date.now()
  };
  flow.set(rawPendingKey, rawPending);
}
else if (
  rawPending.active === true &&
  (rawResponse || rawResponseHex) &&
  pendingCommand &&
  rawCommand &&
  rawCommand === pendingCommand
) {
  data.diag.raw_command = pendingCommand;
  data.diag._last_raw_command_ts = Number(rawPending.ts || Date.now());

  if (rawResponse) {
    data.diag.raw_response = rawResponse;
    data.diag._last_raw_response_ts = Date.now();
  }

  if (rawResponseHex) {
    data.diag.raw_response_hex = rawResponseHex;
    data.diag._last_raw_response_hex_ts = Date.now();
  }

  rawPending = { active: false };
  flow.set(rawPendingKey, rawPending);
}

// -------------------------------------------------
// 3c) SUPPORT COMMANDES
// -------------------------------------------------
if (!data.diag.command_support || typeof data.diag.command_support !== "object") {
  data.diag.command_support = {};
}

function ensureCmdSupport(obj, key) {
  if (!obj[key] || typeof obj[key] !== "object") obj[key] = {};
  ensure(obj[key], "disabled", false);
  ensure(obj[key], "nak_count", 0);
  ensure(obj[key], "last_ok", 0);
  ensure(obj[key], "last_nak", 0);
  ensure(obj[key], "retry_after", 0);
}

ensureCmdSupport(data.diag.command_support, "qpigs2");
ensureCmdSupport(data.diag.command_support, "qet");
ensureCmdSupport(data.diag.command_support, "qey");
ensureCmdSupport(data.diag.command_support, "qem");
ensureCmdSupport(data.diag.command_support, "qed");
