// On évite de purger tant qu'il n'y a pas de contradiction claire

const inv = msg.inverterNum ?? 1;

function clone(obj) {
    return JSON.parse(JSON.stringify(obj || {}));
}

function cleanString(v) {
    return String(v ?? "").trim();
}

function getIdentityFromPayload(payload) {
    const model = cleanString(payload?.diag?.model);
    const serial = cleanString(payload?.diag?.serial);
    const fw_main = cleanString(payload?.diag?.fw_main);

    let fingerprint = "";
    let key = "";

    if (serial) {
        fingerprint = `SERIAL:${serial}`;
        key = `SERIAL:${serial}`;
    } else if (model && fw_main) {
        fingerprint = `MODELFW:${model}|${fw_main}`;
