    }

    return {
        model,
        serial,
        fw_main,
        fingerprint,
        key
    };
}

function buildIdentityVariants(identity) {
    const out = [];
    const seen = new Set();

    function add(v) {
        const s = cleanString(v);
        if (!s || seen.has(s)) return;
        seen.add(s);
        out.push(s);
    }

    add(identity?.serial ? `SERIAL:${identity.serial}` : "");
    add(identity?.model && identity?.fw_main ? `MODELFW:${identity.model}|${identity.fw_main}` : "");
    add(identity?.model ? `MODEL:${identity.model}` : "");
    add(identity?.fw_main ? `FW:${identity.fw_main}` : "");

    return out;
}

function same(a, b) {
    return cleanString(a) && cleanString(b) && cleanString(a) === cleanString(b);
}

// Retourne :
// - match: true si au moins un des 3 éléments communs match
// - contradiction: true si on a une contradiction claire
// - comparableCount: nombre d'éléments comparables présents des 2 côtés
function compareIdentity(savedIdentity, currentIdentity) {
    const saved = {
        serial: cleanString(savedIdentity?.serial),
        model: cleanString(savedIdentity?.model),
        fw_main: cleanString(savedIdentity?.fw_main)
    };

    const curr = {
        serial: cleanString(currentIdentity?.serial),
        model: cleanString(currentIdentity?.model),
        fw_main: cleanString(currentIdentity?.fw_main)
    };

    let comparableCount = 0;
    let matchCount = 0;
    let mismatchCount = 0;

    if (saved.serial && curr.serial) {
        comparableCount++;
        if (saved.serial === curr.serial) matchCount++;
        else mismatchCount++;
    }

    if (saved.model && curr.model) {
        comparableCount++;
        if (saved.model === curr.model) matchCount++;
        else mismatchCount++;
    }

    if (saved.fw_main && curr.fw_main) {
        comparableCount++;
        if (saved.fw_main === curr.fw_main) matchCount++;
        else mismatchCount++;
    }

    const match = matchCount >= 1;

    // Contradiction claire :
    // - serial connu des 2 côtés et différent
    // - ou 2 infos comparables ou plus, toutes différentes, aucune ne match
    let contradiction = false;

    if (saved.serial && curr.serial && saved.serial !== curr.serial) {
        contradiction = true;
    } else if (comparableCount >= 2 && matchCount === 0 && mismatchCount === comparableCount) {
        contradiction = true;
    }

    return {
        match,
        contradiction,
        comparableCount,
        matchCount,
        mismatchCount
    };
}

function getProfileLearnedMap(profile, learnedPersistent, learnedBackup) {
    const savedFp = cleanString(profile?.identity?.fingerprint || "");

    let sourceLearned = clone(profile?.learned || {});
    if (sourceLearned && typeof sourceLearned === "object" && Object.keys(sourceLearned).length > 0) {
        return sourceLearned;
    }

    sourceLearned = clone(learnedPersistent[savedFp] || {});
    if (sourceLearned && typeof sourceLearned === "object" && Object.keys(sourceLearned).length > 0) {
        return sourceLearned;
    }

    sourceLearned = clone(learnedBackup[savedFp] || {});
    if (sourceLearned && typeof sourceLearned === "object" && Object.keys(sourceLearned).length > 0) {
        return sourceLearned;
    }

    return {};
}

const state = msg.payload;
if (!state || typeof state !== "object") return msg;

const identity = getIdentityFromPayload(state);
