// Calculés en permanence, exposés seulement si premium
// -------------------------------------
if (premiumActive) {
  // PV month/year
  if (isMissing(state.pv_energy_month_kwh)) {
    state.pv_energy_month_kwh = calcPvMonth;
    state.diag.pv_energy_month_source = "calculated";
  } else {
    state.diag.pv_energy_month_source = "inverter";
  }

  if (isMissing(state.pv_energy_year_kwh)) {
    state.pv_energy_year_kwh = calcPvYear;
    state.diag.pv_energy_year_source = "calculated";
  } else {
    state.diag.pv_energy_year_source = "inverter";
  }

  // Load month/year
  if (isMissing(state.load_energy_month_kwh)) {
    state.load_energy_month_kwh = calcLoadMonth;
    state.diag.load_energy_month_source = "calculated";
  } else {
    state.diag.load_energy_month_source = "inverter";
  }

  if (isMissing(state.load_energy_year_kwh)) {
    state.load_energy_year_kwh = calcLoadYear;
    state.diag.load_energy_year_source = "calculated";
  } else {
    state.diag.load_energy_year_source = "inverter";
  }

  // Battery charge month/year
  state.battery_charge_month_kwh = calcBattChargeMonth;
  state.battery_charge_year_kwh = calcBattChargeYear;
  state.diag.battery_charge_month_source = "calculated";
  state.diag.battery_charge_year_source = "calculated";

  // Battery discharge month/year
  state.battery_discharge_month_kwh = calcBattDischargeMonth;
  state.battery_discharge_year_kwh = calcBattDischargeYear;
  state.diag.battery_discharge_month_source = "calculated";
  state.diag.battery_discharge_year_source = "calculated";

  // Grid month/year
  state.grid_energy_month_kwh = calcGridMonth;
  state.grid_energy_year_kwh = calcGridYear;
  state.diag.grid_energy_month_source = "calculated";
  state.diag.grid_energy_year_source = "calculated";
} else {
  // S'assure de ne pas exposer les capteurs premium
  delete state.pv_energy_month_kwh;
  delete state.pv_energy_year_kwh;

  delete state.load_energy_month_kwh;
  delete state.load_energy_year_kwh;

  delete state.battery_charge_month_kwh;
  delete state.battery_charge_year_kwh;

  delete state.battery_discharge_month_kwh;
  delete state.battery_discharge_year_kwh;

  delete state.grid_energy_month_kwh;
  delete state.grid_energy_year_kwh;

  delete state.diag.pv_energy_month_source;
  delete state.diag.pv_energy_year_source;

  delete state.diag.load_energy_month_source;
  delete state.diag.load_energy_year_source;

  delete state.diag.battery_charge_month_source;
  delete state.diag.battery_charge_year_source;

  delete state.diag.battery_discharge_month_source;
  delete state.diag.battery_discharge_year_source;

  delete state.diag.grid_energy_month_source;
  delete state.diag.grid_energy_year_source;
}

state._day_key = dayKey;
state._month_key = monthKey;
state._year_key = yearKey;
state._premium_extended_energy = premiumActive;

msg.payload = state;
return msg;

// =====================================
// DAILY ENERGY CALC / FALLBACK
// - Remplit les champs existants si absents
// - Stockage persistant des compteurs journaliers / mensuels / annuels
// - Les compteurs month/year sont calculés en permanence
//   mais exposés uniquement si premium actif
// =====================================

if (!msg.payload || typeof msg.payload !== "object") return msg;

const inv = msg.inverterNum ?? 1;
const state = { ...msg.payload };
const premiumActive = global.get("premium.active") === true;

function toNum(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

function round2(v) {
  const n = Number(v);
  return Number.isFinite(n) ? Math.round((n + Number.EPSILON) * 100) / 100 : null;
}

function isMissing(v) {
  return v === null || v === undefined || !Number.isFinite(Number(v));
}

function getSafeTimezone() {
  let tz = (global.get("addon_timezone") || "UTC").toString().trim();
  if (!tz) tz = "UTC";

  try {
    new Intl.DateTimeFormat("en-CA", { timeZone: tz }).format(new Date());
  } catch (e) {
    tz = "UTC";
  }

  return tz;
}

function localDateParts(d = new Date()) {
  const tz = getSafeTimezone();

  const parts = new Intl.DateTimeFormat("en-CA", {
    timeZone: tz,
    year: "numeric",
    month: "2-digit",
    day: "2-digit"
  }).formatToParts(d);

  const get = (t) => parts.find(p => p.type === t)?.value;
  return {
    year: get("year"),
    month: get("month"),
    day: get("day")
  };
}

function localDayKey(d = new Date()) {
  const p = localDateParts(d);
  return `${p.year}${p.month}${p.day}`;
}

function localMonthKey(d = new Date()) {
  const p = localDateParts(d);
  return `${p.year}${p.month}`;
}

function localYearKey(d = new Date()) {
  const p = localDateParts(d);
  return `${p.year}`;
}

const dayKey = localDayKey(new Date());
const monthKey = localMonthKey(new Date());
const yearKey = localYearKey(new Date());
const nowTs = Date.now();

const memKey = `inv${inv}_daily_energy_mem`;
let mem = flow.get(memKey, "persistent");

if (!mem || typeof mem !== "object") {
  mem = {
    dayKey,
    monthKey,
    yearKey,
    lastTs: null,

    pvLastW: null,
    loadLastW: null,
    battChargeLastW: null,
    battDischargeLastW: null,
    gridLastW: null,

    // today
    pvWh: 0,
    loadWh: 0,
    battChargeWh: 0,
    battDischargeWh: 0,
    gridWh: 0,

    // month
    pvMonthWh: 0,
    loadMonthWh: 0,
    battChargeMonthWh: 0,
    battDischargeMonthWh: 0,
    gridMonthWh: 0,

    // year
    pvYearWh: 0,
    loadYearWh: 0,
    battChargeYearWh: 0,
    battDischargeYearWh: 0,
    gridYearWh: 0
  };
}

// -------------------------------------
// Reset journalier / mensuel / annuel
// -------------------------------------
if (mem.yearKey !== yearKey) {
  mem = {
    dayKey,
    monthKey,
    yearKey,
    lastTs: nowTs,

    pvLastW: null,
    loadLastW: null,
    battChargeLastW: null,
    battDischargeLastW: null,
    gridLastW: null,

    // today
    pvWh: 0,
    loadWh: 0,
    battChargeWh: 0,
    battDischargeWh: 0,
    gridWh: 0,

    // month
    pvMonthWh: 0,
    loadMonthWh: 0,
    battChargeMonthWh: 0,
    battDischargeMonthWh: 0,
    gridMonthWh: 0,

    // year
    pvYearWh: 0,
    loadYearWh: 0,
    battChargeYearWh: 0,
    battDischargeYearWh: 0,
    gridYearWh: 0
  };
} else if (mem.monthKey !== monthKey) {
  mem.dayKey = dayKey;
  mem.monthKey = monthKey;
  mem.yearKey = yearKey;
  mem.lastTs = nowTs;

  mem.pvLastW = null;
  mem.loadLastW = null;
  mem.battChargeLastW = null;
  mem.battDischargeLastW = null;
  mem.gridLastW = null;

  // reset today
  mem.pvWh = 0;
  mem.loadWh = 0;
  mem.battChargeWh = 0;
  mem.battDischargeWh = 0;
  mem.gridWh = 0;

  // reset month
  mem.pvMonthWh = 0;
  mem.loadMonthWh = 0;
  mem.battChargeMonthWh = 0;
  mem.battDischargeMonthWh = 0;
  mem.gridMonthWh = 0;

  // year conservé
} else if (mem.dayKey !== dayKey) {
  mem.dayKey = dayKey;
  mem.monthKey = monthKey;
  mem.yearKey = yearKey;
  mem.lastTs = nowTs;

  mem.pvLastW = null;
  mem.loadLastW = null;
  mem.battChargeLastW = null;
  mem.battDischargeLastW = null;
  mem.gridLastW = null;

  // reset today
  mem.pvWh = 0;
  mem.loadWh = 0;
  mem.battChargeWh = 0;
  mem.battDischargeWh = 0;
  mem.gridWh = 0;
}

// -------------------------------------
// Puissances instantanées
// -------------------------------------
const pvPower = Math.max(0, toNum(state.pv_total_power) ?? 0);
const loadPower = Math.max(0, toNum(state.ac_output_active_power) ?? 0);
const battChargePower = Math.max(0, toNum(state.battery_charge) ?? 0);
const battDischargePower = Math.max(0, toNum(state.battery_discharge) ?? 0);

// grid import uniquement
const gridPowerRaw = toNum(state.grid_power);
const gridPower = Math.max(0, gridPowerRaw ?? 0);

// -------------------------------------
// Intégration trapézoïdale
// -------------------------------------
if (Number.isFinite(mem.lastTs) && nowTs > mem.lastTs) {
  const dtMs = nowTs - mem.lastTs;

  // garde-fou : ignore trou > 10 min
  if (dtMs > 0 && dtMs <= 10 * 60 * 1000) {
    const dtH = dtMs / 3600000;

    if (Number.isFinite(mem.pvLastW)) {
      const inc = ((mem.pvLastW + pvPower) / 2) * dtH;
      mem.pvWh += inc;
      mem.pvMonthWh += inc;
      mem.pvYearWh += inc;
    }

    if (Number.isFinite(mem.loadLastW)) {
      const inc = ((mem.loadLastW + loadPower) / 2) * dtH;
      mem.loadWh += inc;
      mem.loadMonthWh += inc;
      mem.loadYearWh += inc;
    }

    if (Number.isFinite(mem.battChargeLastW)) {
      const inc = ((mem.battChargeLastW + battChargePower) / 2) * dtH;
      mem.battChargeWh += inc;
      mem.battChargeMonthWh += inc;
      mem.battChargeYearWh += inc;
    }

    if (Number.isFinite(mem.battDischargeLastW)) {
      const inc = ((mem.battDischargeLastW + battDischargePower) / 2) * dtH;
      mem.battDischargeWh += inc;
      mem.battDischargeMonthWh += inc;
      mem.battDischargeYearWh += inc;
    }

    if (Number.isFinite(mem.gridLastW)) {
      const inc = ((mem.gridLastW + gridPower) / 2) * dtH;
      mem.gridWh += inc;
      mem.gridMonthWh += inc;
      mem.gridYearWh += inc;
    }
  }
}

mem.dayKey = dayKey;
mem.monthKey = monthKey;
mem.yearKey = yearKey;
mem.lastTs = nowTs;
mem.pvLastW = pvPower;
mem.loadLastW = loadPower;
mem.battChargeLastW = battChargePower;
mem.battDischargeLastW = battDischargePower;
mem.gridLastW = gridPower;

flow.set(memKey, mem, "persistent");

// -------------------------------------
// Valeurs calculées
// -------------------------------------
const calcPvDay = round2(mem.pvWh / 1000);
const calcLoadDay = round2(mem.loadWh / 1000);
const calcBattChargeDay = round2(mem.battChargeWh / 1000);
const calcBattDischargeDay = round2(mem.battDischargeWh / 1000);
const calcGridDay = round2(mem.gridWh / 1000);

const calcPvMonth = round2(mem.pvMonthWh / 1000);
const calcLoadMonth = round2(mem.loadMonthWh / 1000);
const calcBattChargeMonth = round2(mem.battChargeMonthWh / 1000);
const calcBattDischargeMonth = round2(mem.battDischargeMonthWh / 1000);
const calcGridMonth = round2(mem.gridMonthWh / 1000);

const calcPvYear = round2(mem.pvYearWh / 1000);
const calcLoadYear = round2(mem.loadYearWh / 1000);
const calcBattChargeYear = round2(mem.battChargeYearWh / 1000);
const calcBattDischargeYear = round2(mem.battDischargeYearWh / 1000);
const calcGridYear = round2(mem.gridYearWh / 1000);

// -------------------------------------
// Diag
// -------------------------------------
state.diag = state.diag || {};

// -------------------------------------
// Fallback sur les champs existants (FREE)
// -------------------------------------
if (isMissing(state.pv_energy_day_kwh)) {
  state.pv_energy_day_kwh = calcPvDay;
  state.diag.pv_energy_day_source = "calculated";
} else {
  state.diag.pv_energy_day_source = "inverter";
}

if (isMissing(state.load_energy_day_kwh)) {
  state.load_energy_day_kwh = calcLoadDay;
  state.diag.load_energy_day_source = "calculated";
} else {
  state.diag.load_energy_day_source = "inverter";
}

// toujours calculés ici
state.battery_charge_day_kwh = calcBattChargeDay;
state.battery_discharge_day_kwh = calcBattDischargeDay;
state.grid_energy_day_kwh = calcGridDay;

state.diag.battery_charge_day_source = "calculated";
state.diag.battery_discharge_day_source = "calculated";
state.diag.grid_energy_day_source = "calculated";

// -------------------------------------
// Premium month/year
// Calculés en permanence, exposés seulement si premium
// -------------------------------------
if (premiumActive) {
  // PV month/year
  if (isMissing(state.pv_energy_month_kwh)) {
    state.pv_energy_month_kwh = calcPvMonth;
    state.diag.pv_energy_month_source = "calculated";
  } else {
    state.diag.pv_energy_month_source = "inverter";
  }

  if (isMissing(state.pv_energy_year_kwh)) {
    state.pv_energy_year_kwh = calcPvYear;
    state.diag.pv_energy_year_source = "calculated";
  } else {
    state.diag.pv_energy_year_source = "inverter";
  }

  // Load month/year
  if (isMissing(state.load_energy_month_kwh)) {
    state.load_energy_month_kwh = calcLoadMonth;
    state.diag.load_energy_month_source = "calculated";
  } else {
    state.diag.load_energy_month_source = "inverter";
  }

  if (isMissing(state.load_energy_year_kwh)) {
    state.load_energy_year_kwh = calcLoadYear;
    state.diag.load_energy_year_source = "calculated";
  } else {
    state.diag.load_energy_year_source = "inverter";
  }

  // Battery charge month/year
  state.battery_charge_month_kwh = calcBattChargeMonth;
  state.battery_charge_year_kwh = calcBattChargeYear;
  state.diag.battery_charge_month_source = "calculated";
  state.diag.battery_charge_year_source = "calculated";

  // Battery discharge month/year
  state.battery_discharge_month_kwh = calcBattDischargeMonth;
  state.battery_discharge_year_kwh = calcBattDischargeYear;
  state.diag.battery_discharge_month_source = "calculated";
  state.diag.battery_discharge_year_source = "calculated";

  // Grid month/year
  state.grid_energy_month_kwh = calcGridMonth;
  state.grid_energy_year_kwh = calcGridYear;
  state.diag.grid_energy_month_source = "calculated";
  state.diag.grid_energy_year_source = "calculated";
} else {
  // S'assure de ne pas exposer les capteurs premium
  delete state.pv_energy_month_kwh;
  delete state.pv_energy_year_kwh;

  delete state.load_energy_month_kwh;
  delete state.load_energy_year_kwh;

  delete state.battery_charge_month_kwh;
  delete state.battery_charge_year_kwh;

  delete state.battery_discharge_month_kwh;
  delete state.battery_discharge_year_kwh;

  delete state.grid_energy_month_kwh;
  delete state.grid_energy_year_kwh;

  delete state.diag.pv_energy_month_source;
  delete state.diag.pv_energy_year_source;

  delete state.diag.load_energy_month_source;
  delete state.diag.load_energy_year_source;

  delete state.diag.battery_charge_month_source;
  delete state.diag.battery_charge_year_source;

  delete state.diag.battery_discharge_month_source;
  delete state.diag.battery_discharge_year_source;

  delete state.diag.grid_energy_month_source;
  delete state.diag.grid_energy_year_source;
}

state._day_key = dayKey;
state._month_key = monthKey;
state._year_key = yearKey;
state._premium_extended_energy = premiumActive;

msg.payload = state;
return msg;

// ===============================
// PREMIUM CALC
// A placer après "Daily Energy Calc / Fallback"
// et avant "MQTT state publisher"
// ===============================

if (!msg || !msg.payload || typeof msg.payload !== "object") return msg;

const premiumActive = global.get("premium.active") === true;
if (!premiumActive) return msg;

const state = msg.payload;
const inv = msg.inverterNum ?? state.inverter ?? 1;
const now = Date.now();

// --------------------------------------------------
// Helpers
// --------------------------------------------------
function n(v) {
    const x = Number(v);
    return Number.isFinite(x) ? x : null;
}
function nz(v, fb = 0) {
    const x = Number(v);
    return Number.isFinite(x) ? x : fb;
}
function clamp(v, min, max) {
    const x = Number(v);
    if (!Number.isFinite(x)) return min;
    return Math.max(min, Math.min(max, x));
}
function round(v, d = 1) {
    const x = Number(v);
    if (!Number.isFinite(x)) return null;
    const m = Math.pow(10, d);
    return Math.round(x * m) / m;
}
function avg(arr) {
    if (!Array.isArray(arr) || !arr.length) return null;
    const vals = arr.map(Number).filter(Number.isFinite);
    if (!vals.length) return null;
    return vals.reduce((a, b) => a + b, 0) / vals.length;
}
function safeText(v, fb = "unknown") {
    if (v === null || v === undefined || v === "") return fb;
    return String(v);
}
function lower(v) {
    return String(v ?? "").trim().toLowerCase();
}
function setNum(obj, key, val, digits = null) {
    if (!Number.isFinite(Number(val))) return;
    obj[key] = digits == null ? Number(val) : round(val, digits);
}

// --------------------------------------------------
// Battery user config (premium)
// priorité par onduleur, sinon global
// --------------------------------------------------
const sysV = Number(
    global.get(`inverter_${inv}.battery_system_voltage`) ??
    global.get("config.batterySystemVoltage") ??
    global.get("battery_system_voltage") ??
    48
);

const batteryCapacityAh = n(
    global.get(`inverter_${inv}.battery_capacity_ah`) ??
    global.get("battery_capacity_ah")
);

const batteryTotalCapacityKwh = n(
    global.get(`inverter_${inv}.battery_total_capacity_kwh`) ??
    global.get("battery_total_capacity_kwh")
);

// --------------------------------------------------
// Stats premium persistantes
// --------------------------------------------------
const statsKey = `premium_stats_inv${inv}`;
let stats = context.get(statsKey);
if (!stats || typeof stats !== "object") {
    stats = {
        dayKey: "",
        lastTs: now,
        battery: {
            restSamples: [],
            loadSamples: [],
            lowVoltageEventsToday: 0,
            nearLowVoltageMinutesToday: 0,
            heavyDischargeMinutesToday: 0,
            lastLowVoltageFlag: false,
            highCrateMinutesToday: 0,
            veryHighCrateMinutesToday: 0,
            highRelativePowerMinutesToday: 0,
            veryHighRelativePowerMinutesToday: 0
        },
        inverter: {
            highTempMinutesToday: 0,
            severeTempMinutesToday: 0,
            bypassMinutesToday: 0,
            faultMinutesToday: 0
        },
        energy: {
            gridToLoadTodayCalc: 0,
            solarToLoadTodayCalc: 0
        }
    };
}

// --------------------------------------------------
// Reset journalier
// --------------------------------------------------
const d = new Date();
const dayKey = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;

if (stats.dayKey !== dayKey) {
    stats.dayKey = dayKey;
    stats.lastTs = now;

    stats.battery.restSamples = [];
    stats.battery.loadSamples = [];
    stats.battery.lowVoltageEventsToday = 0;
    stats.battery.nearLowVoltageMinutesToday = 0;
    stats.battery.heavyDischargeMinutesToday = 0;
    stats.battery.lastLowVoltageFlag = false;
    stats.battery.highCrateMinutesToday = 0;
    stats.battery.veryHighCrateMinutesToday = 0;
    stats.battery.highRelativePowerMinutesToday = 0;
    stats.battery.veryHighRelativePowerMinutesToday = 0;

    stats.inverter.highTempMinutesToday = 0;
    stats.inverter.severeTempMinutesToday = 0;
    stats.inverter.bypassMinutesToday = 0;
    stats.inverter.faultMinutesToday = 0;

    stats.energy.gridToLoadTodayCalc = 0;
    stats.energy.solarToLoadTodayCalc = 0;
}

// --------------------------------------------------
// Delta temps
// --------------------------------------------------
let dtSec = (now - Number(stats.lastTs || now)) / 1000;
if (!Number.isFinite(dtSec) || dtSec < 0) dtSec = 0;
if (dtSec > 300) dtSec = 300;
stats.lastTs = now;

const dtH = dtSec / 3600;
const dtMin = dtSec / 60;

// --------------------------------------------------
// Valeurs source
// --------------------------------------------------
const loadPower = nz(
    state.ac_output_active_power ??
    state.output_active_power ??
    state.output_power ??
    state.load_power
);

const pv1Power = nz(state.pv1_power ?? state.pv_power);
const pv2Power = nz(state.pv2_power);
const pvTotalPower = Math.max(0, pv1Power + pv2Power);

const batteryVoltage = nz(state.battery_voltage);
const batteryChargeCurrent = Math.max(0, nz(state.battery_charging_current ?? state.battery_charge_current));
const batteryDischargeCurrent = Math.max(0, nz(state.battery_discharge_current));

const batteryChargePower = Math.max(
    0,
    nz(state.battery_charge ?? state.battery_charge_power, batteryVoltage * batteryChargeCurrent)
);

const batteryDischargePower = Math.max(
    0,
    Math.abs(nz(state.battery_discharge ?? state.battery_discharge_power, batteryVoltage * batteryDischargeCurrent))
);

const gridVoltage = Math.max(0, nz(state.grid_voltage ?? state.ac_input_voltage ?? state.input_voltage));

const heatsinkTemp = n(
    state.inverter_heat_sink_temp ??
    state.heatsink_temp ??
    state.inverter_temp
);

const loadToday = Math.max(0, nz(state.load_energy_day_kwh ?? state.load_today));
const solarToday = Math.max(0, nz(state.pv_energy_day_kwh ?? state.solar_today ?? state.pv_today));
const batteryDischargeToday = Math.max(0, nz(state.battery_discharge_day_kwh ?? state.battery_discharge_today));

const gridTodayNativeRaw = n(state.grid_energy_day_kwh ?? state.grid_today);
const hasGridTodayNative = gridTodayNativeRaw !== null && gridTodayNativeRaw >= 0;
const gridTodayNative = hasGridTodayNative ? Math.max(0, gridTodayNativeRaw) : null;

let opMode = safeText(
    state.operation_mode_code ?? state.operation_mode ?? state.qmod_mode,
    ""
).trim().toUpperCase();

if (opMode === "LINE") opMode = "L";
else if (opMode === "BATTERY") opMode = "B";
else if (opMode === "BYPASS") opMode = "Y";
else if (opMode === "FAULT") opMode = "F";
else if (opMode === "CHARGE") opMode = "C";

const gridPresent = gridVoltage >= 150;

// seuils batterie
const underVoltage = n(
    state.params?.qpiri?.battery_under_voltage ??
    state.battery_under_voltage ??
    state.under_voltage
);

const returnGridVoltage = n(
    state.params?.qpiri?.battery_recharge_voltage ??
    state.return_grid_voltage ??
    state.return_to_grid_voltage
);

// --------------------------------------------------
// 1) ENERGY MIX
// On ne publie PAS battery_to_load_today (doublon voulu)
// --------------------------------------------------

// instantané
let solarToLoadPower = Math.min(loadPower, pvTotalPower);

let gridToLoadPower = Math.max(0, loadPower - solarToLoadPower);
if (opMode === "B" && !gridPresent) gridToLoadPower = 0;
if (opMode === "F") gridToLoadPower = 0;

// cumuls
stats.energy.solarToLoadTodayCalc += (solarToLoadPower * dtH) / 1000;
stats.energy.gridToLoadTodayCalc += (gridToLoadPower * dtH) / 1000;

// today finaux
const batteryToLoadToday = Math.max(0, batteryDischargeToday); // utilisé pour les % mais non publié
let gridToLoadToday;
let energyFlowCalcQuality = "estimated";

if (hasGridTodayNative) {
    gridToLoadToday = gridTodayNative;
    energyFlowCalcQuality = "native";
} else {
    gridToLoadToday = Math.max(0, stats.energy.gridToLoadTodayCalc);
}

let solarToLoadToday = Math.max(0, Math.min(loadToday, solarToday));

// borne à loadToday
let sumToday = solarToLoadToday + batteryToLoadToday + gridToLoadToday;
if (loadToday > 0 && sumToday > loadToday) {
    const excess = sumToday - loadToday;
    solarToLoadToday = Math.max(0, solarToLoadToday - excess);
    sumToday = solarToLoadToday + batteryToLoadToday + gridToLoadToday;
}

// si pas de grid natif, résiduel final
if (!hasGridTodayNative && loadToday > 0) {
    gridToLoadToday = Math.max(0, loadToday - solarToLoadToday - batteryToLoadToday);
}

let solarSupplyTodayPct = 0;
let batterySupplyTodayPct = 0;
let gridSupplyTodayPct = 0;

if (loadToday > 0.001) {
    solarSupplyTodayPct = clamp((solarToLoadToday / loadToday) * 100, 0, 100);
    batterySupplyTodayPct = clamp((batteryToLoadToday / loadToday) * 100, 0, 100);
    gridSupplyTodayPct = clamp((gridToLoadToday / loadToday) * 100, 0, 100);

    const totalPct = solarSupplyTodayPct + batterySupplyTodayPct + gridSupplyTodayPct;
    if (Math.abs(totalPct - 100) > 0.2) {
        gridSupplyTodayPct = clamp(gridSupplyTodayPct + (100 - totalPct), 0, 100);
    }
}

setNum(state, "grid_to_load_today", gridToLoadToday, 2);
setNum(state, "solar_supply_today_pct", solarSupplyTodayPct, 1);
setNum(state, "battery_supply_today_pct", batterySupplyTodayPct, 1);
setNum(state, "grid_supply_today_pct", gridSupplyTodayPct, 1);
state.energy_flow_calc_quality = energyFlowCalcQuality;

// --------------------------------------------------
// 2) BATTERY HEALTH
// --------------------------------------------------

// samples repos / en charge
const isResting =
    loadPower < 100 &&
    batteryChargeCurrent < 1 &&
    batteryDischargeCurrent < 1;

const isLoaded =
    batteryDischargeCurrent >= 5 ||
    batteryDischargePower >= 300;

if (batteryVoltage > 0) {
    if (isResting) {
        stats.battery.restSamples.push(batteryVoltage);
        if (stats.battery.restSamples.length > 30) stats.battery.restSamples.shift();
    }
    if (isLoaded) {
        stats.battery.loadSamples.push(batteryVoltage);
        if (stats.battery.loadSamples.length > 30) stats.battery.loadSamples.shift();
    }
}

const restVoltageAvg = avg(stats.battery.restSamples);
const loadVoltageAvg = avg(stats.battery.loadSamples);

let voltageSag = null;
if (restVoltageAvg != null && loadVoltageAvg != null) {
    voltageSag = Math.max(0, restVoltageAvg - loadVoltageAvg);
}

// proximité tension basse
let nearLowVoltage = false;
if (batteryVoltage > 0) {
    if (underVoltage != null && batteryVoltage <= underVoltage + 0.7) {
        nearLowVoltage = true;
    } else if (returnGridVoltage != null && batteryVoltage <= returnGridVoltage + 0.3) {
        nearLowVoltage = true;
    }
}

if (nearLowVoltage) {
    stats.battery.nearLowVoltageMinutesToday += dtMin;
}

const lowVoltageFlag = nearLowVoltage && isLoaded;
if (lowVoltageFlag && !stats.battery.lastLowVoltageFlag) {
    stats.battery.lowVoltageEventsToday += 1;
}
stats.battery.lastLowVoltageFlag = lowVoltageFlag;

// --------------------------------------------------
// Stress relatif selon Ah / kWh / fallback
// --------------------------------------------------
let stressMode = "fallback";
let cRate = null;
let relativePowerRatio = null;

// priorité Ah
if (batteryCapacityAh && batteryCapacityAh > 0) {
    cRate = batteryDischargeCurrent / batteryCapacityAh;
    stressMode = "ah";

    if (cRate >= 0.8) {
        stats.battery.veryHighCrateMinutesToday += dtMin;
    } else if (cRate >= 0.5) {
        stats.battery.highCrateMinutesToday += dtMin;
    }
}
// sinon kWh
else if (batteryTotalCapacityKwh && batteryTotalCapacityKwh > 0) {
    relativePowerRatio = batteryDischargePower / (batteryTotalCapacityKwh * 1000);
    stressMode = "kwh";

    if (relativePowerRatio >= 0.5) {
        stats.battery.veryHighRelativePowerMinutesToday += dtMin;
    } else if (relativePowerRatio >= 0.3) {
        stats.battery.highRelativePowerMinutesToday += dtMin;
    }
}
// fallback doux
else {
    stressMode = "fallback";
    if (batteryDischargePower >= 2500 || batteryDischargeCurrent >= 50) {
        stats.battery.heavyDischargeMinutesToday += dtMin;
    }
}

// --------------------------------------------------
// Score santé batterie
// --------------------------------------------------
let batteryHealthScore = 100;
let batteryHealthReason = "stable voltage";

// sag
if (voltageSag != null) {
    if (voltageSag >= 4.0) {
        batteryHealthScore -= 35;
        batteryHealthReason = "very high voltage sag";
    } else if (voltageSag >= 3.0) {
        batteryHealthScore -= 24;
        batteryHealthReason = "high voltage sag under load";
    } else if (voltageSag >= 2.0) {
        batteryHealthScore -= 14;
        batteryHealthReason = "moderate voltage sag";
    } else if (voltageSag >= 1.2) {
        batteryHealthScore -= 6;
        batteryHealthReason = "light voltage sag";
    }
}

// événements basse tension
if (stats.battery.lowVoltageEventsToday >= 6) {
    batteryHealthScore -= 22;
    batteryHealthReason = "repeated low voltage events";
} else if (stats.battery.lowVoltageEventsToday >= 3) {
    batteryHealthScore -= 12;
    if (batteryHealthReason === "stable voltage") batteryHealthReason = "low voltage events";
} else if (stats.battery.lowVoltageEventsToday >= 1) {
    batteryHealthScore -= 5;
    if (batteryHealthReason === "stable voltage") batteryHealthReason = "single low voltage event";
}

// temps proche sous-tension
if (stats.battery.nearLowVoltageMinutesToday >= 240) {
    batteryHealthScore -= 18;
    batteryHealthReason = "battery often near low voltage";
} else if (stats.battery.nearLowVoltageMinutesToday >= 90) {
    batteryHealthScore -= 8;
    if (batteryHealthReason === "stable voltage") batteryHealthReason = "near low voltage for long periods";
}

// stress relatif
if (stressMode === "ah") {
    if (stats.battery.veryHighCrateMinutesToday >= 90) {
        batteryHealthScore -= 15;
        if (batteryHealthReason === "stable voltage") batteryHealthReason = "very high discharge rate";
    } else if (stats.battery.highCrateMinutesToday >= 120) {
        batteryHealthScore -= 8;
        if (batteryHealthReason === "stable voltage") batteryHealthReason = "high discharge rate";
    }
} else if (stressMode === "kwh") {
    if (stats.battery.veryHighRelativePowerMinutesToday >= 90) {
        batteryHealthScore -= 15;
        if (batteryHealthReason === "stable voltage") batteryHealthReason = "very high relative battery load";
    } else if (stats.battery.highRelativePowerMinutesToday >= 120) {
        batteryHealthScore -= 8;
        if (batteryHealthReason === "stable voltage") batteryHealthReason = "high relative battery load";
    }
} else {
    if (stats.battery.heavyDischargeMinutesToday >= 120) {
        batteryHealthScore -= 8;
        if (batteryHealthReason === "stable voltage") batteryHealthReason = "heavy discharge stress";
    }
}

batteryHealthScore = clamp(Math.round(batteryHealthScore), 0, 100);

let batteryHealthState = "unknown";
if (batteryVoltage <= 0) {
    batteryHealthState = "unknown";
    batteryHealthReason = "no battery voltage data";
} else if (batteryHealthScore >= 90) {
    batteryHealthState = "excellent";
} else if (batteryHealthScore >= 75) {
    batteryHealthState = "good";
} else if (batteryHealthScore >= 55) {
    batteryHealthState = "fair";
} else if (batteryHealthScore >= 35) {
    batteryHealthState = "weak";
} else {
    batteryHealthState = "critical";
}

// --------------------------------------------------
// Stress batterie
// --------------------------------------------------
let batteryStressState = "low";

if (stressMode === "ah") {
    const severeByRate =
        stats.battery.veryHighCrateMinutesToday >= 180 &&
        (stats.battery.nearLowVoltageMinutesToday >= 120 || stats.battery.lowVoltageEventsToday >= 3);

    if (severeByRate) {
        batteryStressState = "severe";
    } else if (
        stats.battery.veryHighCrateMinutesToday >= 60 ||
        stats.battery.highCrateMinutesToday >= 180 ||
        stats.battery.nearLowVoltageMinutesToday >= 180 ||
        stats.battery.lowVoltageEventsToday >= 3
    ) {
        batteryStressState = "high";
    } else if (
        stats.battery.highCrateMinutesToday >= 45 ||
        stats.battery.nearLowVoltageMinutesToday >= 60 ||
        stats.battery.lowVoltageEventsToday >= 1
    ) {
        batteryStressState = "moderate";
    }
}
else if (stressMode === "kwh") {
    const severeByRelativePower =
        stats.battery.veryHighRelativePowerMinutesToday >= 180 &&
        (stats.battery.nearLowVoltageMinutesToday >= 120 || stats.battery.lowVoltageEventsToday >= 3);

    if (severeByRelativePower) {
        batteryStressState = "severe";
    } else if (
        stats.battery.veryHighRelativePowerMinutesToday >= 60 ||
        stats.battery.highRelativePowerMinutesToday >= 180 ||
        stats.battery.nearLowVoltageMinutesToday >= 180 ||
        stats.battery.lowVoltageEventsToday >= 3
    ) {
        batteryStressState = "high";
    } else if (
        stats.battery.highRelativePowerMinutesToday >= 45 ||
        stats.battery.nearLowVoltageMinutesToday >= 60 ||
        stats.battery.lowVoltageEventsToday >= 1
    ) {
        batteryStressState = "moderate";
    }
}
else {
    if (
        stats.battery.heavyDischargeMinutesToday >= 240 &&
        (stats.battery.nearLowVoltageMinutesToday >= 120 || stats.battery.lowVoltageEventsToday >= 3)
    ) {
        batteryStressState = "severe";
    } else if (
        stats.battery.heavyDischargeMinutesToday >= 120 ||
        stats.battery.nearLowVoltageMinutesToday >= 180 ||
        stats.battery.lowVoltageEventsToday >= 3
    ) {
        batteryStressState = "high";
    } else if (
        stats.battery.heavyDischargeMinutesToday >= 45 ||
        stats.battery.nearLowVoltageMinutesToday >= 60 ||
        stats.battery.lowVoltageEventsToday >= 1
    ) {
        batteryStressState = "moderate";
    }
}

setNum(state, "battery_health_score", batteryHealthScore, 0);
state.battery_health_state = batteryHealthState;
state.battery_health_reason = batteryHealthReason;
state.battery_stress_state = batteryStressState;

// --------------------------------------------------
// 3) INVERTER HEALTH
// --------------------------------------------------
const warnStateText = lower(state.diag?.warn_state);
const warnDetailsText = lower(state.diag?.warn_details);
const faultStateText = lower(state.diag?.fault_state);

const warnLineFail =
    warnStateText.includes("line") ||
    warnDetailsText.includes("line fail");

const warnBatteryLow =
    warnStateText.includes("battery low") ||
    warnDetailsText.includes("battery low");

const warnOverload =
    warnStateText.includes("overload") ||
    warnDetailsText.includes("overload");

const warnOverTemp =
    warnStateText.includes("over temp") ||
    warnStateText.includes("overtemperature") ||
    warnDetailsText.includes("over temperature");

const warnFanLock =
    warnStateText.includes("fan") ||
    warnDetailsText.includes("fan lock");

const faultActive =
    opMode === "F" ||
    (faultStateText && faultStateText !== "ok" && faultStateText !== "none" && faultStateText !== "unknown");

const bypassActive = opMode === "Y";

if (heatsinkTemp != null) {
    if (heatsinkTemp >= 65) stats.inverter.highTempMinutesToday += dtMin;
    if (heatsinkTemp >= 75) stats.inverter.severeTempMinutesToday += dtMin;
}
if (faultActive) stats.inverter.faultMinutesToday += dtMin;
if (bypassActive) stats.inverter.bypassMinutesToday += dtMin;

let inverterHealthScore = 100;

if (heatsinkTemp != null) {
    if (heatsinkTemp >= 80) inverterHealthScore -= 35;
    else if (heatsinkTemp >= 72) inverterHealthScore -= 22;
    else if (heatsinkTemp >= 65) inverterHealthScore -= 12;
    else if (heatsinkTemp >= 58) inverterHealthScore -= 5;
}

if (warnLineFail) inverterHealthScore -= 5;
if (warnBatteryLow) inverterHealthScore -= 10;
if (warnOverload) inverterHealthScore -= 20;
if (warnOverTemp) inverterHealthScore -= 30;
if (warnFanLock) inverterHealthScore -= 35;
if (faultActive) inverterHealthScore -= 40;
if (stats.inverter.bypassMinutesToday >= 120) inverterHealthScore -= 10;

inverterHealthScore = clamp(Math.round(inverterHealthScore), 0, 100);

let inverterHealthState = "unknown";
if (faultActive || inverterHealthScore < 35) {
    inverterHealthState = "critical";
} else if (inverterHealthScore >= 90) {
    inverterHealthState = "excellent";
} else if (inverterHealthScore >= 75) {
    inverterHealthState = "good";
} else if (inverterHealthScore >= 55) {
    inverterHealthState = "warning";
} else {
    inverterHealthState = "degraded";
}

let inverterStressState = "low";
if (
    faultActive ||
    warnOverTemp ||
    warnFanLock ||
    stats.inverter.severeTempMinutesToday >= 30
) {
    inverterStressState = "severe";
} else if (
    warnOverload ||
    (heatsinkTemp != null && heatsinkTemp >= 72) ||
    stats.inverter.highTempMinutesToday >= 60
) {
    inverterStressState = "high";
} else if (
    warnBatteryLow ||
    warnLineFail ||
    (heatsinkTemp != null && heatsinkTemp >= 60)
) {
    inverterStressState = "moderate";
}

setNum(state, "inverter_health_score", inverterHealthScore, 0);
state.inverter_health_state = inverterHealthState;
state.inverter_stress_state = inverterStressState;

// --------------------------------------------------
// 4) DIAG premium
// --------------------------------------------------
state.diag = state.diag || {};
setNum(state.diag, "premium_voltage_sag", voltageSag, 2);
setNum(state.diag, "premium_rest_voltage_avg", restVoltageAvg, 2);
setNum(state.diag, "premium_load_voltage_avg", loadVoltageAvg, 2);
setNum(state.diag, "premium_battery_low_voltage_events_today", stats.battery.lowVoltageEventsToday, 0);
setNum(state.diag, "premium_battery_near_low_voltage_minutes_today", stats.battery.nearLowVoltageMinutesToday, 0);
setNum(state.diag, "premium_battery_high_crate_minutes_today", stats.battery.highCrateMinutesToday, 0);
setNum(state.diag, "premium_battery_very_high_crate_minutes_today", stats.battery.veryHighCrateMinutesToday, 0);
setNum(state.diag, "premium_battery_high_relative_power_minutes_today", stats.battery.highRelativePowerMinutesToday, 0);
setNum(state.diag, "premium_battery_very_high_relative_power_minutes_today", stats.battery.veryHighRelativePowerMinutesToday, 0);
setNum(state.diag, "premium_inverter_high_temp_minutes_today", stats.inverter.highTempMinutesToday, 0);
setNum(state.diag, "premium_inverter_fault_minutes_today", stats.inverter.faultMinutesToday, 0);
state.diag.premium_battery_stress_mode = stressMode;
if (cRate != null) setNum(state.diag, "premium_battery_c_rate", cRate, 3);
if (relativePowerRatio != null) setNum(state.diag, "premium_battery_relative_power_ratio", relativePowerRatio, 3);

// --------------------------------------------------
// Save
// --------------------------------------------------
context.set(statsKey, stats);
msg.payload = state;
return msg;

// ===============================
// PREMIUM CALC
// A placer après "Daily Energy Calc / Fallback"
// et avant "MQTT state publisher"
// ===============================

if (!msg || !msg.payload || typeof msg.payload !== "object") return msg;

const premiumActive = global.get("premium.active") === true;
if (!premiumActive) return msg;

const state = msg.payload;
const inv = msg.inverterNum ?? state.inverter ?? 1;
const now = Date.now();

// --------------------------------------------------
// Helpers
// --------------------------------------------------
function n(v) {
    const x = Number(v);
    return Number.isFinite(x) ? x : null;
}
function nz(v, fb = 0) {
    const x = Number(v);
    return Number.isFinite(x) ? x : fb;
}
function clamp(v, min, max) {
    const x = Number(v);
    if (!Number.isFinite(x)) return min;
    return Math.max(min, Math.min(max, x));
}
function round(v, d = 1) {
    const x = Number(v);
    if (!Number.isFinite(x)) return null;
    const m = Math.pow(10, d);
    return Math.round(x * m) / m;
}
function avg(arr) {
    if (!Array.isArray(arr) || !arr.length) return null;
    const vals = arr.map(Number).filter(Number.isFinite);
    if (!vals.length) return null;
    return vals.reduce((a, b) => a + b, 0) / vals.length;
}
function safeText(v, fb = "unknown") {
    if (v === null || v === undefined || v === "") return fb;
    return String(v);
}
function lower(v) {
    return String(v ?? "").trim().toLowerCase();
}
function setNum(obj, key, val, digits = null) {
    if (!Number.isFinite(Number(val))) return;
    obj[key] = digits == null ? Number(val) : round(val, digits);
}

// --------------------------------------------------
// Battery user config (premium)
// priorité par onduleur, sinon global
// --------------------------------------------------
const sysV = Number(
    global.get(`inverter_${inv}.battery_system_voltage`) ??
    global.get("config.batterySystemVoltage") ??
    global.get("battery_system_voltage") ??
    48
);

const batteryCapacityAh = n(
    global.get(`inverter_${inv}.battery_capacity_ah`) ??
    global.get("battery_capacity_ah")
);

const batteryTotalCapacityKwh = n(
    global.get(`inverter_${inv}.battery_total_capacity_kwh`) ??
    global.get("battery_total_capacity_kwh")
);

// --------------------------------------------------
// Stats premium persistantes
// --------------------------------------------------
const statsKey = `premium_stats_inv${inv}`;
let stats = context.get(statsKey);
if (!stats || typeof stats !== "object") {
    stats = {
        dayKey: "",
        lastTs: now,
        battery: {
            restSamples: [],
            loadSamples: [],
            lowVoltageEventsToday: 0,
            nearLowVoltageMinutesToday: 0,
            heavyDischargeMinutesToday: 0,
            lastLowVoltageFlag: false,
            highCrateMinutesToday: 0,
            veryHighCrateMinutesToday: 0,
            highRelativePowerMinutesToday: 0,
            veryHighRelativePowerMinutesToday: 0
        },
        inverter: {
            highTempMinutesToday: 0,
            severeTempMinutesToday: 0,
            bypassMinutesToday: 0,
            faultMinutesToday: 0
        },
        energy: {
            gridToLoadTodayCalc: 0,
            solarToLoadTodayCalc: 0
        }
    };
}

// --------------------------------------------------
// Reset journalier
// --------------------------------------------------
const d = new Date();
const dayKey = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;

if (stats.dayKey !== dayKey) {
    stats.dayKey = dayKey;
    stats.lastTs = now;

    stats.battery.restSamples = [];
    stats.battery.loadSamples = [];
    stats.battery.lowVoltageEventsToday = 0;
    stats.battery.nearLowVoltageMinutesToday = 0;
    stats.battery.heavyDischargeMinutesToday = 0;
    stats.battery.lastLowVoltageFlag = false;
    stats.battery.highCrateMinutesToday = 0;
    stats.battery.veryHighCrateMinutesToday = 0;
    stats.battery.highRelativePowerMinutesToday = 0;
    stats.battery.veryHighRelativePowerMinutesToday = 0;

    stats.inverter.highTempMinutesToday = 0;
    stats.inverter.severeTempMinutesToday = 0;
    stats.inverter.bypassMinutesToday = 0;
    stats.inverter.faultMinutesToday = 0;

    stats.energy.gridToLoadTodayCalc = 0;
    stats.energy.solarToLoadTodayCalc = 0;
}

// --------------------------------------------------
// Delta temps
// --------------------------------------------------
let dtSec = (now - Number(stats.lastTs || now)) / 1000;
if (!Number.isFinite(dtSec) || dtSec < 0) dtSec = 0;
if (dtSec > 300) dtSec = 300;
stats.lastTs = now;

const dtH = dtSec / 3600;
const dtMin = dtSec / 60;

// --------------------------------------------------
// Valeurs source
// --------------------------------------------------
const loadPower = nz(
    state.ac_output_active_power ??
    state.output_active_power ??
    state.output_power ??
    state.load_power
);

const pv1Power = nz(state.pv1_power ?? state.pv_power);
const pv2Power = nz(state.pv2_power);
const pvTotalPower = Math.max(0, pv1Power + pv2Power);

const batteryVoltage = nz(state.battery_voltage);
const batteryChargeCurrent = Math.max(0, nz(state.battery_charging_current ?? state.battery_charge_current));
const batteryDischargeCurrent = Math.max(0, nz(state.battery_discharge_current));

const batteryChargePower = Math.max(
    0,
    nz(state.battery_charge ?? state.battery_charge_power, batteryVoltage * batteryChargeCurrent)
);

const batteryDischargePower = Math.max(
    0,
    Math.abs(nz(state.battery_discharge ?? state.battery_discharge_power, batteryVoltage * batteryDischargeCurrent))
);

const gridVoltage = Math.max(0, nz(state.grid_voltage ?? state.ac_input_voltage ?? state.input_voltage));

const heatsinkTemp = n(
    state.inverter_heat_sink_temp ??
    state.heatsink_temp ??
    state.inverter_temp
);

const loadToday = Math.max(0, nz(state.load_energy_day_kwh ?? state.load_today));
const solarToday = Math.max(0, nz(state.pv_energy_day_kwh ?? state.solar_today ?? state.pv_today));
const batteryDischargeToday = Math.max(0, nz(state.battery_discharge_day_kwh ?? state.battery_discharge_today));

const gridTodayNativeRaw = n(state.grid_energy_day_kwh ?? state.grid_today);
const hasGridTodayNative = gridTodayNativeRaw !== null && gridTodayNativeRaw >= 0;
const gridTodayNative = hasGridTodayNative ? Math.max(0, gridTodayNativeRaw) : null;

let opMode = safeText(
    state.operation_mode_code ?? state.operation_mode ?? state.qmod_mode,
    ""
).trim().toUpperCase();

if (opMode === "LINE") opMode = "L";
else if (opMode === "BATTERY") opMode = "B";
else if (opMode === "BYPASS") opMode = "Y";
else if (opMode === "FAULT") opMode = "F";
else if (opMode === "CHARGE") opMode = "C";

const gridPresent = gridVoltage >= 150;

// seuils batterie
const underVoltage = n(
    state.params?.qpiri?.battery_under_voltage ??
    state.battery_under_voltage ??
    state.under_voltage
);

const returnGridVoltage = n(
    state.params?.qpiri?.battery_recharge_voltage ??
    state.return_grid_voltage ??
    state.return_to_grid_voltage
);

// --------------------------------------------------
// 1) ENERGY MIX
// On ne publie PAS battery_to_load_today (doublon voulu)
// --------------------------------------------------

// instantané
let solarToLoadPower = Math.min(loadPower, pvTotalPower);

let gridToLoadPower = Math.max(0, loadPower - solarToLoadPower);
if (opMode === "B" && !gridPresent) gridToLoadPower = 0;
if (opMode === "F") gridToLoadPower = 0;

// cumuls
stats.energy.solarToLoadTodayCalc += (solarToLoadPower * dtH) / 1000;
stats.energy.gridToLoadTodayCalc += (gridToLoadPower * dtH) / 1000;

// today finaux
const batteryToLoadToday = Math.max(0, batteryDischargeToday); // utilisé pour les % mais non publié
let gridToLoadToday;
let energyFlowCalcQuality = "estimated";

if (hasGridTodayNative) {
    gridToLoadToday = gridTodayNative;
    energyFlowCalcQuality = "native";
} else {
    gridToLoadToday = Math.max(0, stats.energy.gridToLoadTodayCalc);
}

let solarToLoadToday = Math.max(0, Math.min(loadToday, solarToday));

// borne à loadToday
let sumToday = solarToLoadToday + batteryToLoadToday + gridToLoadToday;
if (loadToday > 0 && sumToday > loadToday) {
    const excess = sumToday - loadToday;
    solarToLoadToday = Math.max(0, solarToLoadToday - excess);
    sumToday = solarToLoadToday + batteryToLoadToday + gridToLoadToday;
}

// si pas de grid natif, résiduel final
if (!hasGridTodayNative && loadToday > 0) {
    gridToLoadToday = Math.max(0, loadToday - solarToLoadToday - batteryToLoadToday);
}

let solarSupplyTodayPct = 0;
let batterySupplyTodayPct = 0;
let gridSupplyTodayPct = 0;

if (loadToday > 0.001) {
    solarSupplyTodayPct = clamp((solarToLoadToday / loadToday) * 100, 0, 100);
    batterySupplyTodayPct = clamp((batteryToLoadToday / loadToday) * 100, 0, 100);
    gridSupplyTodayPct = clamp((gridToLoadToday / loadToday) * 100, 0, 100);

    const totalPct = solarSupplyTodayPct + batterySupplyTodayPct + gridSupplyTodayPct;
    if (Math.abs(totalPct - 100) > 0.2) {
        gridSupplyTodayPct = clamp(gridSupplyTodayPct + (100 - totalPct), 0, 100);
    }
}

setNum(state, "grid_to_load_today", gridToLoadToday, 2);
setNum(state, "solar_supply_today_pct", solarSupplyTodayPct, 1);
setNum(state, "battery_supply_today_pct", batterySupplyTodayPct, 1);
setNum(state, "grid_supply_today_pct", gridSupplyTodayPct, 1);
state.energy_flow_calc_quality = energyFlowCalcQuality;

// --------------------------------------------------
// 2) BATTERY HEALTH
// --------------------------------------------------

// samples repos / en charge
const isResting =
    loadPower < 100 &&
    batteryChargeCurrent < 1 &&
    batteryDischargeCurrent < 1;

const isLoaded =
    batteryDischargeCurrent >= 5 ||
    batteryDischargePower >= 300;

if (batteryVoltage > 0) {
    if (isResting) {
        stats.battery.restSamples.push(batteryVoltage);
        if (stats.battery.restSamples.length > 30) stats.battery.restSamples.shift();
    }
    if (isLoaded) {
        stats.battery.loadSamples.push(batteryVoltage);
        if (stats.battery.loadSamples.length > 30) stats.battery.loadSamples.shift();
    }
}

const restVoltageAvg = avg(stats.battery.restSamples);
const loadVoltageAvg = avg(stats.battery.loadSamples);

let voltageSag = null;
if (restVoltageAvg != null && loadVoltageAvg != null) {
    voltageSag = Math.max(0, restVoltageAvg - loadVoltageAvg);
}

// proximité tension basse
let nearLowVoltage = false;
if (batteryVoltage > 0) {
    if (underVoltage != null && batteryVoltage <= underVoltage + 0.7) {
        nearLowVoltage = true;
    } else if (returnGridVoltage != null && batteryVoltage <= returnGridVoltage + 0.3) {
        nearLowVoltage = true;
    }
}

if (nearLowVoltage) {
    stats.battery.nearLowVoltageMinutesToday += dtMin;
}

const lowVoltageFlag = nearLowVoltage && isLoaded;
if (lowVoltageFlag && !stats.battery.lastLowVoltageFlag) {
    stats.battery.lowVoltageEventsToday += 1;
}
stats.battery.lastLowVoltageFlag = lowVoltageFlag;

// --------------------------------------------------
// Stress relatif selon Ah / kWh / fallback
// --------------------------------------------------
let stressMode = "fallback";
let cRate = null;
let relativePowerRatio = null;

// priorité Ah
if (batteryCapacityAh && batteryCapacityAh > 0) {
    cRate = batteryDischargeCurrent / batteryCapacityAh;
    stressMode = "ah";

    if (cRate >= 0.8) {
        stats.battery.veryHighCrateMinutesToday += dtMin;
    } else if (cRate >= 0.5) {
        stats.battery.highCrateMinutesToday += dtMin;
    }
}
// sinon kWh
else if (batteryTotalCapacityKwh && batteryTotalCapacityKwh > 0) {
    relativePowerRatio = batteryDischargePower / (batteryTotalCapacityKwh * 1000);
    stressMode = "kwh";

    if (relativePowerRatio >= 0.5) {
        stats.battery.veryHighRelativePowerMinutesToday += dtMin;
    } else if (relativePowerRatio >= 0.3) {
        stats.battery.highRelativePowerMinutesToday += dtMin;
    }
}
// fallback doux
else {
    stressMode = "fallback";
    if (batteryDischargePower >= 2500 || batteryDischargeCurrent >= 50) {
        stats.battery.heavyDischargeMinutesToday += dtMin;
    }
}

// --------------------------------------------------
// Score santé batterie
// --------------------------------------------------
let batteryHealthScore = 100;
let batteryHealthReason = "stable voltage";

// sag
if (voltageSag != null) {
    if (voltageSag >= 4.0) {
        batteryHealthScore -= 35;
        batteryHealthReason = "very high voltage sag";
    } else if (voltageSag >= 3.0) {
        batteryHealthScore -= 24;
        batteryHealthReason = "high voltage sag under load";
    } else if (voltageSag >= 2.0) {
        batteryHealthScore -= 14;
        batteryHealthReason = "moderate voltage sag";
    } else if (voltageSag >= 1.2) {
        batteryHealthScore -= 6;
        batteryHealthReason = "light voltage sag";
    }
}

// événements basse tension
if (stats.battery.lowVoltageEventsToday >= 6) {
    batteryHealthScore -= 22;
    batteryHealthReason = "repeated low voltage events";
} else if (stats.battery.lowVoltageEventsToday >= 3) {
    batteryHealthScore -= 12;
    if (batteryHealthReason === "stable voltage") batteryHealthReason = "low voltage events";
} else if (stats.battery.lowVoltageEventsToday >= 1) {
    batteryHealthScore -= 5;
    if (batteryHealthReason === "stable voltage") batteryHealthReason = "single low voltage event";
}

// temps proche sous-tension
if (stats.battery.nearLowVoltageMinutesToday >= 240) {
    batteryHealthScore -= 18;
    batteryHealthReason = "battery often near low voltage";
} else if (stats.battery.nearLowVoltageMinutesToday >= 90) {
    batteryHealthScore -= 8;
    if (batteryHealthReason === "stable voltage") batteryHealthReason = "near low voltage for long periods";
}

// stress relatif
if (stressMode === "ah") {
    if (stats.battery.veryHighCrateMinutesToday >= 90) {
        batteryHealthScore -= 15;
        if (batteryHealthReason === "stable voltage") batteryHealthReason = "very high discharge rate";
    } else if (stats.battery.highCrateMinutesToday >= 120) {
        batteryHealthScore -= 8;
        if (batteryHealthReason === "stable voltage") batteryHealthReason = "high discharge rate";
    }
} else if (stressMode === "kwh") {
    if (stats.battery.veryHighRelativePowerMinutesToday >= 90) {
        batteryHealthScore -= 15;
        if (batteryHealthReason === "stable voltage") batteryHealthReason = "very high relative battery load";
    } else if (stats.battery.highRelativePowerMinutesToday >= 120) {
        batteryHealthScore -= 8;
        if (batteryHealthReason === "stable voltage") batteryHealthReason = "high relative battery load";
    }
} else {
    if (stats.battery.heavyDischargeMinutesToday >= 120) {
        batteryHealthScore -= 8;
        if (batteryHealthReason === "stable voltage") batteryHealthReason = "heavy discharge stress";
    }
}

batteryHealthScore = clamp(Math.round(batteryHealthScore), 0, 100);

let batteryHealthState = "unknown";
if (batteryVoltage <= 0) {
    batteryHealthState = "unknown";
    batteryHealthReason = "no battery voltage data";
} else if (batteryHealthScore >= 90) {
    batteryHealthState = "excellent";
} else if (batteryHealthScore >= 75) {
    batteryHealthState = "good";
} else if (batteryHealthScore >= 55) {
    batteryHealthState = "fair";
} else if (batteryHealthScore >= 35) {
    batteryHealthState = "weak";
} else {
    batteryHealthState = "critical";
}

// --------------------------------------------------
// Stress batterie
// --------------------------------------------------
let batteryStressState = "low";

if (stressMode === "ah") {
    const severeByRate =
        stats.battery.veryHighCrateMinutesToday >= 180 &&
        (stats.battery.nearLowVoltageMinutesToday >= 120 || stats.battery.lowVoltageEventsToday >= 3);

    if (severeByRate) {
        batteryStressState = "severe";
    } else if (
        stats.battery.veryHighCrateMinutesToday >= 60 ||
        stats.battery.highCrateMinutesToday >= 180 ||
        stats.battery.nearLowVoltageMinutesToday >= 180 ||
        stats.battery.lowVoltageEventsToday >= 3
    ) {
        batteryStressState = "high";
    } else if (
        stats.battery.highCrateMinutesToday >= 45 ||
        stats.battery.nearLowVoltageMinutesToday >= 60 ||
        stats.battery.lowVoltageEventsToday >= 1
    ) {
        batteryStressState = "moderate";
    }
}
else if (stressMode === "kwh") {
    const severeByRelativePower =
        stats.battery.veryHighRelativePowerMinutesToday >= 180 &&
        (stats.battery.nearLowVoltageMinutesToday >= 120 || stats.battery.lowVoltageEventsToday >= 3);

    if (severeByRelativePower) {
        batteryStressState = "severe";
    } else if (
        stats.battery.veryHighRelativePowerMinutesToday >= 60 ||
        stats.battery.highRelativePowerMinutesToday >= 180 ||
        stats.battery.nearLowVoltageMinutesToday >= 180 ||
        stats.battery.lowVoltageEventsToday >= 3
    ) {
        batteryStressState = "high";
    } else if (
        stats.battery.highRelativePowerMinutesToday >= 45 ||
        stats.battery.nearLowVoltageMinutesToday >= 60 ||
        stats.battery.lowVoltageEventsToday >= 1
    ) {
        batteryStressState = "moderate";
    }
}
else {
    if (
        stats.battery.heavyDischargeMinutesToday >= 240 &&
        (stats.battery.nearLowVoltageMinutesToday >= 120 || stats.battery.lowVoltageEventsToday >= 3)
    ) {
        batteryStressState = "severe";
    } else if (
        stats.battery.heavyDischargeMinutesToday >= 120 ||
        stats.battery.nearLowVoltageMinutesToday >= 180 ||
        stats.battery.lowVoltageEventsToday >= 3
    ) {
        batteryStressState = "high";
    } else if (
        stats.battery.heavyDischargeMinutesToday >= 45 ||
        stats.battery.nearLowVoltageMinutesToday >= 60 ||
        stats.battery.lowVoltageEventsToday >= 1
    ) {
        batteryStressState = "moderate";
    }
}

setNum(state, "battery_health_score", batteryHealthScore, 0);
state.battery_health_state = batteryHealthState;
state.battery_health_reason = batteryHealthReason;
state.battery_stress_state = batteryStressState;

// --------------------------------------------------
// 3) INVERTER HEALTH
// --------------------------------------------------
const warnStateText = lower(state.diag?.warn_state);
const warnDetailsText = lower(state.diag?.warn_details);
const faultStateText = lower(state.diag?.fault_state);

const warnLineFail =
    warnStateText.includes("line") ||
    warnDetailsText.includes("line fail");

const warnBatteryLow =
    warnStateText.includes("battery low") ||
    warnDetailsText.includes("battery low");

const warnOverload =
    warnStateText.includes("overload") ||
    warnDetailsText.includes("overload");

const warnOverTemp =
    warnStateText.includes("over temp") ||
    warnStateText.includes("overtemperature") ||
    warnDetailsText.includes("over temperature");

const warnFanLock =
    warnStateText.includes("fan") ||
    warnDetailsText.includes("fan lock");

const faultActive =
    opMode === "F" ||
    (faultStateText && faultStateText !== "ok" && faultStateText !== "none" && faultStateText !== "unknown");

const bypassActive = opMode === "Y";

if (heatsinkTemp != null) {
    if (heatsinkTemp >= 65) stats.inverter.highTempMinutesToday += dtMin;
    if (heatsinkTemp >= 75) stats.inverter.severeTempMinutesToday += dtMin;
}
if (faultActive) stats.inverter.faultMinutesToday += dtMin;
if (bypassActive) stats.inverter.bypassMinutesToday += dtMin;

let inverterHealthScore = 100;

if (heatsinkTemp != null) {
    if (heatsinkTemp >= 80) inverterHealthScore -= 35;
    else if (heatsinkTemp >= 72) inverterHealthScore -= 22;
    else if (heatsinkTemp >= 65) inverterHealthScore -= 12;
    else if (heatsinkTemp >= 58) inverterHealthScore -= 5;
}

if (warnLineFail) inverterHealthScore -= 5;
if (warnBatteryLow) inverterHealthScore -= 10;
if (warnOverload) inverterHealthScore -= 20;
if (warnOverTemp) inverterHealthScore -= 30;
if (warnFanLock) inverterHealthScore -= 35;
if (faultActive) inverterHealthScore -= 40;
if (stats.inverter.bypassMinutesToday >= 120) inverterHealthScore -= 10;

inverterHealthScore = clamp(Math.round(inverterHealthScore), 0, 100);

let inverterHealthState = "unknown";
if (faultActive || inverterHealthScore < 35) {
    inverterHealthState = "critical";
} else if (inverterHealthScore >= 90) {
    inverterHealthState = "excellent";
} else if (inverterHealthScore >= 75) {
    inverterHealthState = "good";
} else if (inverterHealthScore >= 55) {
    inverterHealthState = "warning";
} else {
    inverterHealthState = "degraded";
}

let inverterStressState = "low";
if (
    faultActive ||
    warnOverTemp ||
    warnFanLock ||
    stats.inverter.severeTempMinutesToday >= 30
) {
    inverterStressState = "severe";
} else if (
    warnOverload ||
    (heatsinkTemp != null && heatsinkTemp >= 72) ||
    stats.inverter.highTempMinutesToday >= 60
) {
    inverterStressState = "high";
} else if (
    warnBatteryLow ||
    warnLineFail ||
    (heatsinkTemp != null && heatsinkTemp >= 60)
) {
    inverterStressState = "moderate";
}

setNum(state, "inverter_health_score", inverterHealthScore, 0);
state.inverter_health_state = inverterHealthState;
state.inverter_stress_state = inverterStressState;

// --------------------------------------------------
// 4) DIAG premium
// --------------------------------------------------
state.diag = state.diag || {};
setNum(state.diag, "premium_voltage_sag", voltageSag, 2);
setNum(state.diag, "premium_rest_voltage_avg", restVoltageAvg, 2);
setNum(state.diag, "premium_load_voltage_avg", loadVoltageAvg, 2);
setNum(state.diag, "premium_battery_low_voltage_events_today", stats.battery.lowVoltageEventsToday, 0);
setNum(state.diag, "premium_battery_near_low_voltage_minutes_today", stats.battery.nearLowVoltageMinutesToday, 0);
setNum(state.diag, "premium_battery_high_crate_minutes_today", stats.battery.highCrateMinutesToday, 0);
setNum(state.diag, "premium_battery_very_high_crate_minutes_today", stats.battery.veryHighCrateMinutesToday, 0);
setNum(state.diag, "premium_battery_high_relative_power_minutes_today", stats.battery.highRelativePowerMinutesToday, 0);
setNum(state.diag, "premium_battery_very_high_relative_power_minutes_today", stats.battery.veryHighRelativePowerMinutesToday, 0);
setNum(state.diag, "premium_inverter_high_temp_minutes_today", stats.inverter.highTempMinutesToday, 0);
setNum(state.diag, "premium_inverter_fault_minutes_today", stats.inverter.faultMinutesToday, 0);
state.diag.premium_battery_stress_mode = stressMode;
if (cRate != null) setNum(state.diag, "premium_battery_c_rate", cRate, 3);
if (relativePowerRatio != null) setNum(state.diag, "premium_battery_relative_power_ratio", relativePowerRatio, 3);

// --------------------------------------------------
// Save
// --------------------------------------------------
context.set(statsKey, stats);
msg.payload = state;
return msg;

// ===============================
// PREMIUM CALC
// A placer après "Daily Energy Calc / Fallback"
// et avant "MQTT state publisher"
// ===============================

if (!msg || !msg.payload || typeof msg.payload !== "object") return msg;

const premiumActive = global.get("premium.active") === true;
if (!premiumActive) return msg;

const state = msg.payload;
const inv = msg.inverterNum ?? state.inverter ?? 1;
const now = Date.now();

// --------------------------------------------------
// Helpers
// --------------------------------------------------
function n(v) {
    const x = Number(v);
    return Number.isFinite(x) ? x : null;
}
function nz(v, fb = 0) {
    const x = Number(v);
    return Number.isFinite(x) ? x : fb;
}
function clamp(v, min, max) {
    const x = Number(v);
    if (!Number.isFinite(x)) return min;
    return Math.max(min, Math.min(max, x));
}
function round(v, d = 1) {
    const x = Number(v);
    if (!Number.isFinite(x)) return null;
    const m = Math.pow(10, d);
    return Math.round(x * m) / m;
}
function avg(arr) {
    if (!Array.isArray(arr) || !arr.length) return null;
    const vals = arr.map(Number).filter(Number.isFinite);
    if (!vals.length) return null;
    return vals.reduce((a, b) => a + b, 0) / vals.length;
}
function safeText(v, fb = "unknown") {
    if (v === null || v === undefined || v === "") return fb;
    return String(v);
}
function lower(v) {
    return String(v ?? "").trim().toLowerCase();
}
function setNum(obj, key, val, digits = null) {
    if (!Number.isFinite(Number(val))) return;
    obj[key] = digits == null ? Number(val) : round(val, digits);
}

// --------------------------------------------------
// Battery user config (premium)
// priorité par onduleur, sinon global
// --------------------------------------------------
const sysV = Number(
    global.get(`inverter_${inv}.battery_system_voltage`) ??
    global.get("config.batterySystemVoltage") ??
    global.get("battery_system_voltage") ??
    48
);

const batteryCapacityAh = n(
    global.get(`inverter_${inv}.battery_capacity_ah`) ??
    global.get("battery_capacity_ah")
);

const batteryTotalCapacityKwh = n(
    global.get(`inverter_${inv}.battery_total_capacity_kwh`) ??
    global.get("battery_total_capacity_kwh")
);

// --------------------------------------------------
// Stats premium persistantes
// --------------------------------------------------
const statsKey = `premium_stats_inv${inv}`;
let stats = context.get(statsKey);
if (!stats || typeof stats !== "object") {
    stats = {
        dayKey: "",
        lastTs: now,
        battery: {
            restSamples: [],
            loadSamples: [],
            lowVoltageEventsToday: 0,
            nearLowVoltageMinutesToday: 0,
            heavyDischargeMinutesToday: 0,
            lastLowVoltageFlag: false,
            highCrateMinutesToday: 0,
            veryHighCrateMinutesToday: 0,
            highRelativePowerMinutesToday: 0,
            veryHighRelativePowerMinutesToday: 0
        },
        inverter: {
            highTempMinutesToday: 0,
            severeTempMinutesToday: 0,
            bypassMinutesToday: 0,
            faultMinutesToday: 0
        },
        energy: {
            gridToLoadTodayCalc: 0,
            solarToLoadTodayCalc: 0
        }
    };
}

// --------------------------------------------------
// Reset journalier
// --------------------------------------------------
const d = new Date();
const dayKey = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;

if (stats.dayKey !== dayKey) {
    stats.dayKey = dayKey;
    stats.lastTs = now;

    stats.battery.restSamples = [];
    stats.battery.loadSamples = [];
    stats.battery.lowVoltageEventsToday = 0;
    stats.battery.nearLowVoltageMinutesToday = 0;
    stats.battery.heavyDischargeMinutesToday = 0;
    stats.battery.lastLowVoltageFlag = false;
    stats.battery.highCrateMinutesToday = 0;
    stats.battery.veryHighCrateMinutesToday = 0;
    stats.battery.highRelativePowerMinutesToday = 0;
    stats.battery.veryHighRelativePowerMinutesToday = 0;

    stats.inverter.highTempMinutesToday = 0;
    stats.inverter.severeTempMinutesToday = 0;
    stats.inverter.bypassMinutesToday = 0;
    stats.inverter.faultMinutesToday = 0;

    stats.energy.gridToLoadTodayCalc = 0;
    stats.energy.solarToLoadTodayCalc = 0;
}

// --------------------------------------------------
// Delta temps
// --------------------------------------------------
let dtSec = (now - Number(stats.lastTs || now)) / 1000;
if (!Number.isFinite(dtSec) || dtSec < 0) dtSec = 0;
if (dtSec > 300) dtSec = 300;
stats.lastTs = now;

const dtH = dtSec / 3600;
const dtMin = dtSec / 60;

// --------------------------------------------------
// Valeurs source
// --------------------------------------------------
const loadPower = nz(
    state.ac_output_active_power ??
    state.output_active_power ??
    state.output_power ??
    state.load_power
);

const pv1Power = nz(state.pv1_power ?? state.pv_power);
const pv2Power = nz(state.pv2_power);
const pvTotalPower = Math.max(0, pv1Power + pv2Power);

const batteryVoltage = nz(state.battery_voltage);
const batteryChargeCurrent = Math.max(0, nz(state.battery_charging_current ?? state.battery_charge_current));
const batteryDischargeCurrent = Math.max(0, nz(state.battery_discharge_current));

const batteryChargePower = Math.max(
    0,
    nz(state.battery_charge ?? state.battery_charge_power, batteryVoltage * batteryChargeCurrent)
);

const batteryDischargePower = Math.max(
    0,
    Math.abs(nz(state.battery_discharge ?? state.battery_discharge_power, batteryVoltage * batteryDischargeCurrent))
);

const gridVoltage = Math.max(0, nz(state.grid_voltage ?? state.ac_input_voltage ?? state.input_voltage));

const heatsinkTemp = n(
    state.inverter_heat_sink_temp ??
    state.heatsink_temp ??
    state.inverter_temp
);

const loadToday = Math.max(0, nz(state.load_energy_day_kwh ?? state.load_today));
const solarToday = Math.max(0, nz(state.pv_energy_day_kwh ?? state.solar_today ?? state.pv_today));
const batteryDischargeToday = Math.max(0, nz(state.battery_discharge_day_kwh ?? state.battery_discharge_today));

const gridTodayNativeRaw = n(state.grid_energy_day_kwh ?? state.grid_today);
const hasGridTodayNative = gridTodayNativeRaw !== null && gridTodayNativeRaw >= 0;
const gridTodayNative = hasGridTodayNative ? Math.max(0, gridTodayNativeRaw) : null;

let opMode = safeText(
    state.operation_mode_code ?? state.operation_mode ?? state.qmod_mode,
    ""
).trim().toUpperCase();

if (opMode === "LINE") opMode = "L";
else if (opMode === "BATTERY") opMode = "B";
else if (opMode === "BYPASS") opMode = "Y";
else if (opMode === "FAULT") opMode = "F";
else if (opMode === "CHARGE") opMode = "C";

const gridPresent = gridVoltage >= 150;

// seuils batterie
const underVoltage = n(
    state.params?.qpiri?.battery_under_voltage ??
    state.battery_under_voltage ??
    state.under_voltage
);

const returnGridVoltage = n(
    state.params?.qpiri?.battery_recharge_voltage ??
    state.return_grid_voltage ??
    state.return_to_grid_voltage
);

// --------------------------------------------------
// 1) ENERGY MIX
// On ne publie PAS battery_to_load_today (doublon voulu)
// --------------------------------------------------

// instantané
let solarToLoadPower = Math.min(loadPower, pvTotalPower);

let gridToLoadPower = Math.max(0, loadPower - solarToLoadPower);
if (opMode === "B" && !gridPresent) gridToLoadPower = 0;
if (opMode === "F") gridToLoadPower = 0;

// cumuls
stats.energy.solarToLoadTodayCalc += (solarToLoadPower * dtH) / 1000;
stats.energy.gridToLoadTodayCalc += (gridToLoadPower * dtH) / 1000;

// today finaux
const batteryToLoadToday = Math.max(0, batteryDischargeToday); // utilisé pour les % mais non publié
let gridToLoadToday;
let energyFlowCalcQuality = "estimated";

if (hasGridTodayNative) {
    gridToLoadToday = gridTodayNative;
    energyFlowCalcQuality = "native";
} else {
    gridToLoadToday = Math.max(0, stats.energy.gridToLoadTodayCalc);
}

let solarToLoadToday = Math.max(0, Math.min(loadToday, solarToday));

// borne à loadToday
let sumToday = solarToLoadToday + batteryToLoadToday + gridToLoadToday;
if (loadToday > 0 && sumToday > loadToday) {
    const excess = sumToday - loadToday;
    solarToLoadToday = Math.max(0, solarToLoadToday - excess);
    sumToday = solarToLoadToday + batteryToLoadToday + gridToLoadToday;
}

// si pas de grid natif, résiduel final
if (!hasGridTodayNative && loadToday > 0) {
    gridToLoadToday = Math.max(0, loadToday - solarToLoadToday - batteryToLoadToday);
}

let solarSupplyTodayPct = 0;
let batterySupplyTodayPct = 0;
let gridSupplyTodayPct = 0;

if (loadToday > 0.001) {
    solarSupplyTodayPct = clamp((solarToLoadToday / loadToday) * 100, 0, 100);
    batterySupplyTodayPct = clamp((batteryToLoadToday / loadToday) * 100, 0, 100);
    gridSupplyTodayPct = clamp((gridToLoadToday / loadToday) * 100, 0, 100);

    const totalPct = solarSupplyTodayPct + batterySupplyTodayPct + gridSupplyTodayPct;
    if (Math.abs(totalPct - 100) > 0.2) {
        gridSupplyTodayPct = clamp(gridSupplyTodayPct + (100 - totalPct), 0, 100);
    }
}

setNum(state, "grid_to_load_today", gridToLoadToday, 2);
setNum(state, "solar_supply_today_pct", solarSupplyTodayPct, 1);
setNum(state, "battery_supply_today_pct", batterySupplyTodayPct, 1);
setNum(state, "grid_supply_today_pct", gridSupplyTodayPct, 1);
state.energy_flow_calc_quality = energyFlowCalcQuality;

// --------------------------------------------------
// 2) BATTERY HEALTH
// --------------------------------------------------

// samples repos / en charge
const isResting =
    loadPower < 100 &&
    batteryChargeCurrent < 1 &&
    batteryDischargeCurrent < 1;

const isLoaded =
    batteryDischargeCurrent >= 5 ||
    batteryDischargePower >= 300;

if (batteryVoltage > 0) {
    if (isResting) {
        stats.battery.restSamples.push(batteryVoltage);
        if (stats.battery.restSamples.length > 30) stats.battery.restSamples.shift();
    }
    if (isLoaded) {
        stats.battery.loadSamples.push(batteryVoltage);
        if (stats.battery.loadSamples.length > 30) stats.battery.loadSamples.shift();
    }
}

const restVoltageAvg = avg(stats.battery.restSamples);
const loadVoltageAvg = avg(stats.battery.loadSamples);

let voltageSag = null;
if (restVoltageAvg != null && loadVoltageAvg != null) {
    voltageSag = Math.max(0, restVoltageAvg - loadVoltageAvg);
}

// proximité tension basse
let nearLowVoltage = false;
if (batteryVoltage > 0) {
    if (underVoltage != null && batteryVoltage <= underVoltage + 0.7) {
        nearLowVoltage = true;
    } else if (returnGridVoltage != null && batteryVoltage <= returnGridVoltage + 0.3) {
        nearLowVoltage = true;
    }
}

if (nearLowVoltage) {
    stats.battery.nearLowVoltageMinutesToday += dtMin;
}

const lowVoltageFlag = nearLowVoltage && isLoaded;
if (lowVoltageFlag && !stats.battery.lastLowVoltageFlag) {
    stats.battery.lowVoltageEventsToday += 1;
}
stats.battery.lastLowVoltageFlag = lowVoltageFlag;

// --------------------------------------------------
// Stress relatif selon Ah / kWh / fallback
// --------------------------------------------------
let stressMode = "fallback";
let cRate = null;
let relativePowerRatio = null;

// priorité Ah
if (batteryCapacityAh && batteryCapacityAh > 0) {
    cRate = batteryDischargeCurrent / batteryCapacityAh;
    stressMode = "ah";

    if (cRate >= 0.8) {
        stats.battery.veryHighCrateMinutesToday += dtMin;
    } else if (cRate >= 0.5) {
        stats.battery.highCrateMinutesToday += dtMin;
    }
}
// sinon kWh
else if (batteryTotalCapacityKwh && batteryTotalCapacityKwh > 0) {
    relativePowerRatio = batteryDischargePower / (batteryTotalCapacityKwh * 1000);
    stressMode = "kwh";

    if (relativePowerRatio >= 0.5) {
        stats.battery.veryHighRelativePowerMinutesToday += dtMin;
    } else if (relativePowerRatio >= 0.3) {
        stats.battery.highRelativePowerMinutesToday += dtMin;
    }
}
// fallback doux
else {
    stressMode = "fallback";
    if (batteryDischargePower >= 2500 || batteryDischargeCurrent >= 50) {
        stats.battery.heavyDischargeMinutesToday += dtMin;
    }
}

// --------------------------------------------------
// Score santé batterie
// --------------------------------------------------
let batteryHealthScore = 100;
let batteryHealthReason = "stable voltage";

// sag
if (voltageSag != null) {
    if (voltageSag >= 4.0) {
        batteryHealthScore -= 35;
        batteryHealthReason = "very high voltage sag";
    } else if (voltageSag >= 3.0) {
        batteryHealthScore -= 24;
        batteryHealthReason = "high voltage sag under load";
    } else if (voltageSag >= 2.0) {
        batteryHealthScore -= 14;
        batteryHealthReason = "moderate voltage sag";
    } else if (voltageSag >= 1.2) {
        batteryHealthScore -= 6;
        batteryHealthReason = "light voltage sag";
    }
}

// événements basse tension
if (stats.battery.lowVoltageEventsToday >= 6) {
    batteryHealthScore -= 22;
    batteryHealthReason = "repeated low voltage events";
} else if (stats.battery.lowVoltageEventsToday >= 3) {
    batteryHealthScore -= 12;
    if (batteryHealthReason === "stable voltage") batteryHealthReason = "low voltage events";
} else if (stats.battery.lowVoltageEventsToday >= 1) {
    batteryHealthScore -= 5;
    if (batteryHealthReason === "stable voltage") batteryHealthReason = "single low voltage event";
}

// temps proche sous-tension
if (stats.battery.nearLowVoltageMinutesToday >= 240) {
    batteryHealthScore -= 18;
    batteryHealthReason = "battery often near low voltage";
} else if (stats.battery.nearLowVoltageMinutesToday >= 90) {
    batteryHealthScore -= 8;
    if (batteryHealthReason === "stable voltage") batteryHealthReason = "near low voltage for long periods";
}

// stress relatif
if (stressMode === "ah") {
    if (stats.battery.veryHighCrateMinutesToday >= 90) {
        batteryHealthScore -= 15;
        if (batteryHealthReason === "stable voltage") batteryHealthReason = "very high discharge rate";
    } else if (stats.battery.highCrateMinutesToday >= 120) {
        batteryHealthScore -= 8;
        if (batteryHealthReason === "stable voltage") batteryHealthReason = "high discharge rate";
    }
} else if (stressMode === "kwh") {
    if (stats.battery.veryHighRelativePowerMinutesToday >= 90) {
        batteryHealthScore -= 15;
        if (batteryHealthReason === "stable voltage") batteryHealthReason = "very high relative battery load";
    } else if (stats.battery.highRelativePowerMinutesToday >= 120) {
        batteryHealthScore -= 8;
        if (batteryHealthReason === "stable voltage") batteryHealthReason = "high relative battery load";
    }
} else {
    if (stats.battery.heavyDischargeMinutesToday >= 120) {
        batteryHealthScore -= 8;
        if (batteryHealthReason === "stable voltage") batteryHealthReason = "heavy discharge stress";
    }
}

batteryHealthScore = clamp(Math.round(batteryHealthScore), 0, 100);

let batteryHealthState = "unknown";
if (batteryVoltage <= 0) {
    batteryHealthState = "unknown";
    batteryHealthReason = "no battery voltage data";
} else if (batteryHealthScore >= 90) {
    batteryHealthState = "excellent";
} else if (batteryHealthScore >= 75) {
    batteryHealthState = "good";
} else if (batteryHealthScore >= 55) {
    batteryHealthState = "fair";
} else if (batteryHealthScore >= 35) {
    batteryHealthState = "weak";
} else {
    batteryHealthState = "critical";
}

// --------------------------------------------------
// Stress batterie
// --------------------------------------------------
let batteryStressState = "low";

if (stressMode === "ah") {
    const severeByRate =
        stats.battery.veryHighCrateMinutesToday >= 180 &&
        (stats.battery.nearLowVoltageMinutesToday >= 120 || stats.battery.lowVoltageEventsToday >= 3);

    if (severeByRate) {
        batteryStressState = "severe";
    } else if (
        stats.battery.veryHighCrateMinutesToday >= 60 ||
        stats.battery.highCrateMinutesToday >= 180 ||
        stats.battery.nearLowVoltageMinutesToday >= 180 ||
        stats.battery.lowVoltageEventsToday >= 3
    ) {
        batteryStressState = "high";
    } else if (
        stats.battery.highCrateMinutesToday >= 45 ||
        stats.battery.nearLowVoltageMinutesToday >= 60 ||
        stats.battery.lowVoltageEventsToday >= 1
    ) {
        batteryStressState = "moderate";
    }
}
else if (stressMode === "kwh") {
    const severeByRelativePower =
        stats.battery.veryHighRelativePowerMinutesToday >= 180 &&
        (stats.battery.nearLowVoltageMinutesToday >= 120 || stats.battery.lowVoltageEventsToday >= 3);

    if (severeByRelativePower) {
        batteryStressState = "severe";
    } else if (
        stats.battery.veryHighRelativePowerMinutesToday >= 60 ||
        stats.battery.highRelativePowerMinutesToday >= 180 ||
        stats.battery.nearLowVoltageMinutesToday >= 180 ||
        stats.battery.lowVoltageEventsToday >= 3
    ) {
        batteryStressState = "high";
    } else if (
        stats.battery.highRelativePowerMinutesToday >= 45 ||
        stats.battery.nearLowVoltageMinutesToday >= 60 ||
        stats.battery.lowVoltageEventsToday >= 1
    ) {
        batteryStressState = "moderate";
    }
}
else {
    if (
        stats.battery.heavyDischargeMinutesToday >= 240 &&
        (stats.battery.nearLowVoltageMinutesToday >= 120 || stats.battery.lowVoltageEventsToday >= 3)
    ) {
        batteryStressState = "severe";
    } else if (
        stats.battery.heavyDischargeMinutesToday >= 120 ||
        stats.battery.nearLowVoltageMinutesToday >= 180 ||
        stats.battery.lowVoltageEventsToday >= 3
    ) {
        batteryStressState = "high";
    } else if (
        stats.battery.heavyDischargeMinutesToday >= 45 ||
        stats.battery.nearLowVoltageMinutesToday >= 60 ||
        stats.battery.lowVoltageEventsToday >= 1
    ) {
        batteryStressState = "moderate";
    }
}

setNum(state, "battery_health_score", batteryHealthScore, 0);
state.battery_health_state = batteryHealthState;
state.battery_health_reason = batteryHealthReason;
state.battery_stress_state = batteryStressState;

// --------------------------------------------------
// 3) INVERTER HEALTH
// --------------------------------------------------
const warnStateText = lower(state.diag?.warn_state);
const warnDetailsText = lower(state.diag?.warn_details);
const faultStateText = lower(state.diag?.fault_state);

const warnLineFail =
    warnStateText.includes("line") ||
    warnDetailsText.includes("line fail");

const warnBatteryLow =
    warnStateText.includes("battery low") ||
    warnDetailsText.includes("battery low");

const warnOverload =
    warnStateText.includes("overload") ||
    warnDetailsText.includes("overload");

const warnOverTemp =
    warnStateText.includes("over temp") ||
    warnStateText.includes("overtemperature") ||
    warnDetailsText.includes("over temperature");

const warnFanLock =
    warnStateText.includes("fan") ||
    warnDetailsText.includes("fan lock");

const faultActive =
    opMode === "F" ||
    (faultStateText && faultStateText !== "ok" && faultStateText !== "none" && faultStateText !== "unknown");

const bypassActive = opMode === "Y";

if (heatsinkTemp != null) {
    if (heatsinkTemp >= 65) stats.inverter.highTempMinutesToday += dtMin;
    if (heatsinkTemp >= 75) stats.inverter.severeTempMinutesToday += dtMin;
}
if (faultActive) stats.inverter.faultMinutesToday += dtMin;
if (bypassActive) stats.inverter.bypassMinutesToday += dtMin;

let inverterHealthScore = 100;

if (heatsinkTemp != null) {
    if (heatsinkTemp >= 80) inverterHealthScore -= 35;
    else if (heatsinkTemp >= 72) inverterHealthScore -= 22;
    else if (heatsinkTemp >= 65) inverterHealthScore -= 12;
    else if (heatsinkTemp >= 58) inverterHealthScore -= 5;
}

if (warnLineFail) inverterHealthScore -= 5;
if (warnBatteryLow) inverterHealthScore -= 10;
if (warnOverload) inverterHealthScore -= 20;
if (warnOverTemp) inverterHealthScore -= 30;
if (warnFanLock) inverterHealthScore -= 35;
if (faultActive) inverterHealthScore -= 40;
if (stats.inverter.bypassMinutesToday >= 120) inverterHealthScore -= 10;

inverterHealthScore = clamp(Math.round(inverterHealthScore), 0, 100);

let inverterHealthState = "unknown";
if (faultActive || inverterHealthScore < 35) {
    inverterHealthState = "critical";
} else if (inverterHealthScore >= 90) {
    inverterHealthState = "excellent";
} else if (inverterHealthScore >= 75) {
    inverterHealthState = "good";
} else if (inverterHealthScore >= 55) {
    inverterHealthState = "warning";
} else {
    inverterHealthState = "degraded";
}

let inverterStressState = "low";
if (
    faultActive ||
    warnOverTemp ||
    warnFanLock ||
    stats.inverter.severeTempMinutesToday >= 30
) {
    inverterStressState = "severe";
} else if (
    warnOverload ||
    (heatsinkTemp != null && heatsinkTemp >= 72) ||
    stats.inverter.highTempMinutesToday >= 60
) {
    inverterStressState = "high";
} else if (
    warnBatteryLow ||
    warnLineFail ||
    (heatsinkTemp != null && heatsinkTemp >= 60)
) {
    inverterStressState = "moderate";
}

setNum(state, "inverter_health_score", inverterHealthScore, 0);
state.inverter_health_state = inverterHealthState;
state.inverter_stress_state = inverterStressState;

// --------------------------------------------------
// 4) DIAG premium
// --------------------------------------------------
state.diag = state.diag || {};
setNum(state.diag, "premium_voltage_sag", voltageSag, 2);
setNum(state.diag, "premium_rest_voltage_avg", restVoltageAvg, 2);
setNum(state.diag, "premium_load_voltage_avg", loadVoltageAvg, 2);
setNum(state.diag, "premium_battery_low_voltage_events_today", stats.battery.lowVoltageEventsToday, 0);
setNum(state.diag, "premium_battery_near_low_voltage_minutes_today", stats.battery.nearLowVoltageMinutesToday, 0);
setNum(state.diag, "premium_battery_high_crate_minutes_today", stats.battery.highCrateMinutesToday, 0);
setNum(state.diag, "premium_battery_very_high_crate_minutes_today", stats.battery.veryHighCrateMinutesToday, 0);
setNum(state.diag, "premium_battery_high_relative_power_minutes_today", stats.battery.highRelativePowerMinutesToday, 0);
setNum(state.diag, "premium_battery_very_high_relative_power_minutes_today", stats.battery.veryHighRelativePowerMinutesToday, 0);
setNum(state.diag, "premium_inverter_high_temp_minutes_today", stats.inverter.highTempMinutesToday, 0);
setNum(state.diag, "premium_inverter_fault_minutes_today", stats.inverter.faultMinutesToday, 0);
state.diag.premium_battery_stress_mode = stressMode;
if (cRate != null) setNum(state.diag, "premium_battery_c_rate", cRate, 3);
if (relativePowerRatio != null) setNum(state.diag, "premium_battery_relative_power_ratio", relativePowerRatio, 3);

// --------------------------------------------------
// Save
// --------------------------------------------------
context.set(statsKey, stats);
msg.payload = state;
return msg;

// =======================
// MQTT DISCOVERY - VOLTRONIC (SAFE TEMPLATES)
// VERSION PAR ONDULEUR
// Compatible serial + gateway/tcp
//
// A CHANGER SELON LE NOEUD :
//   const inv = 1;   -> onduleur 1
//   const inv = 2;   -> onduleur 2
//   const inv = 3;   -> onduleur 3
// =======================

const inv = 1; // <-- CHANGER ICI : 1 / 2 / 3

const HA_PREFIX = "homeassistant";
const BASE_TOPIC = "voltronic";

// =======================
// Helpers
// =======================
function cleanString(v) {
  return String(v ?? "").trim();
}

function isTwoChoiceOutputPriorityEnabled(inv, cfg) {
  return (
    global.get(`inverter_${inv}.output_priority_2choices`) === true ||
    cfg?.outputPriorityTwoChoices === true
  );
}

function stableObjectId(objectId) {
  return `voltronic_inv${inv}_${objectId}`;
}

function entityDomainFromTopic(topic) {
  const parts = String(topic || "").split("/");
  return parts.length >= 2 ? parts[1] : "sensor";
}

// =======================
// Premium status
// =======================
const premiumActive = global.get("premium.active") === true;

// =======================
// Battery system voltage (24/48)
// =======================
const sysV = Number(
  global.get("config.batterySystemVoltage") ||
  global.get("battery_system_voltage") ||
  48
);
const is24 = (sysV === 24);

const V_RANGES = is24 ? {
  bulk: { min: 24, max: 30, step: 0.1 },
  float: { min: 24, max: 30, step: 0.1 },
  returnGrid: { min: 22, max: 25.5, step: 0.5 },
  reDischarge: { min: 24, max: 29, step: 0.5 },
  under: { min: 20, max: 27, step: 0.5 }
} : {
  bulk: { min: 40, max: 65, step: 0.1 },
  float: { min: 40, max: 65, step: 0.1 },
  returnGrid: { min: 40, max: 65, step: 0.1 },
  reDischarge: { min: 40, max: 65, step: 0.1 },
  under: { min: 40, max: 65, step: 0.1 }
};

// =======================
// Config inverter depuis parse options
// =======================
const invCfgAll = global.get("config.invCfg") || {};
const enabledInvs = Array.isArray(global.get("config.invertersList"))
  ? global.get("config.invertersList").map(Number).filter(n => [1, 2, 3].includes(n))
  : [];

const cfg = invCfgAll[inv] || {};
const enabled = enabledInvs.includes(inv);

// display mode
const displayMode = String(
  global.get(`inverter_${inv}.display_mode`) ||
  cfg.displayMode ||
  "modern"
).trim();

const outputPriorityTwoChoices = isTwoChoiceOutputPriorityEnabled(inv, cfg);

// signature de config pour ce discovery
const signature = JSON.stringify({
  enabled,
  transport: cfg.transport || "",
  serialPort: cfg.serialPort || "",
  gwHost: cfg.gwHost || "",
  gwPort: cfg.gwPort || "",
  batterySystemVoltage: sysV,
  displayMode,
  outputPriorityTwoChoices,
  premiumActive
});

const lastSigKey = `inv${inv}_discovery_signature`;
const topicsKey = `inv${inv}_discovery_topics`;
const lastSig = flow.get(lastSigKey);
const changed = (lastSig !== signature);

// -----------------------
// Jinja helpers (SAFE)
// -----------------------
const jNum = (path, fallback = 0) => `{{ ${path} | default(${fallback}, true) }}`;
const jStr = (path, fallback = "unknown") => `{{ ${path} | default('${fallback}', true) }}`;
const jDeep = (expr) => `{{ ${expr} }}`;

// Common deep roots
const QPIRI = `value_json.get('params', {}).get('qpiri', {})`;
const QDOP = `value_json.get('params', {}).get('qdop', {})`;

// Topics inverter
const base = `${BASE_TOPIC}/${inv}`;
const state_topic = `${base}/state`;
const availability_topic = `${base}/availability`;
const set_base = `${base}/set`;

const device = {
  identifiers: [`voltronic_inv_${inv}`],
  name: `Voltronic Inverter ${inv}`,
  manufacturer: "Voltronic",
  model: "Axpert/Voltronic"
};

const publishedTopics = [];

// =======================
// Display mode helpers
// =======================
function isLegacyMode(mode) {
  return String(mode || "").startsWith("legacy");
}

function getOutputPriorityOptions(mode, twoChoices) {
  if (twoChoices) {
    if (isLegacyMode(mode)) return ["SUB", "SBU"];
    return ["SolarUtilityBat", "SolarBatUtility"];
  }
  if (isLegacyMode(mode)) return ["USB", "SUB", "SBU"];
  return ["UtilitySolarBat", "SolarUtilityBat", "SolarBatUtility"];
}

function getOutputPriorityValueTpl(mode, twoChoices) {
  if (twoChoices) {
    if (isLegacyMode(mode)) {
      return `{% set v = ${QPIRI}.get('output_source_priority') %}
{% if v in ['SUB','SBU'] %}{{ v }}
{% elif v in ['SolarUtilityBat'] %}SUB
{% elif v in ['SolarBatUtility'] %}SBU
{% else %}{{ {0:'SUB',1:'SBU',2:'SBU',3:'SBU'}.get((${QPIRI}.get('output_source_priority_code', 0) | int), 'SUB') }}{% endif %}`;
    }
    return `{% set v = ${QPIRI}.get('output_source_priority') %}
{% if v in ['SolarUtilityBat','SolarBatUtility'] %}{{ v }}
{% elif v in ['SUB'] %}SolarUtilityBat
{% elif v in ['SBU'] %}SolarBatUtility
{% else %}{{ {0:'SolarUtilityBat',1:'SolarBatUtility',2:'SolarBatUtility',3:'SolarBatUtility'}.get((${QPIRI}.get('output_source_priority_code', 0) | int), 'SolarUtilityBat') }}{% endif %}`;
  }

  if (isLegacyMode(mode)) {
    return `{% set v = ${QPIRI}.get('output_source_priority') %}
{% if v in ['USB','SUB','SBU'] %}{{ v }}
{% elif v == 'UtilitySolarBat' %}USB
{% elif v == 'SolarUtilityBat' %}SUB
{% elif v == 'SolarBatUtility' %}SBU
{% else %}{{ {0:'USB',1:'SUB',2:'SBU',3:'SBU'}.get((${QPIRI}.get('output_source_priority_code', 0) | int), 'SBU') }}{% endif %}`;
  }

  return `{% set v = ${QPIRI}.get('output_source_priority') %}
{% if v in ['UtilitySolarBat','SolarUtilityBat','SolarBatUtility'] %}{{ v }}
{% elif v == 'USB' %}UtilitySolarBat
{% elif v == 'SUB' %}SolarUtilityBat
{% elif v == 'SBU' %}SolarBatUtility
{% else %}{{ {0:'UtilitySolarBat',1:'SolarUtilityBat',2:'SolarBatUtility',3:'SolarBatUtility'}.get((${QPIRI}.get('output_source_priority_code', 0) | int), 'SolarBatUtility') }}{% endif %}`;
}

function getChargerPriorityOptions(mode) {
  if (isLegacyMode(mode)) return ["CSO", "SNU", "OSO"];
  return ["Solar first", "Solar + Utility", "Only solar"];
}

function getChargerPriorityValueTpl(mode) {
  if (isLegacyMode(mode)) {
    return `{% set v = ${QPIRI}.get('charger_source_priority') %}
{% if v in ['CSO','SNU','OSO'] %}{{ v }}
{% elif v == 'Solar first' %}CSO
{% elif v == 'Solar + Utility' %}SNU
{% elif v == 'Only solar' %}OSO
{% else %}{{ {0:'CSO',1:'SNU',2:'OSO',3:'OSO'}.get((${QPIRI}.get('charger_source_priority_code', 0) | int), 'CSO') }}{% endif %}`;
  }

  return `{% set v = ${QPIRI}.get('charger_source_priority') %}
{% if v in ['Solar first','Solar + Utility','Only solar'] %}{{ v }}
{% elif v == 'CSO' %}Solar first
{% elif v == 'SNU' %}Solar + Utility
{% elif v == 'OSO' %}Only solar
{% else %}{{ {0:'Solar first',1:'Solar + Utility',2:'Only solar',3:'Only solar'}.get((${QPIRI}.get('charger_source_priority_code', 0) | int), 'Solar first') }}{% endif %}`;
}

// -----------------------
// Builders
// -----------------------
function sensorCfg(objectId, name, unit, device_class, state_class, valueTpl, extra = {}) {
  const uid = stableObjectId(objectId);
  const topic = `${HA_PREFIX}/sensor/${uid}/config`;
  const domain = entityDomainFromTopic(topic);

  const payload = {
    name,
    unique_id: uid,
    default_entity_id: `${domain}.${uid}`,
    state_topic,
    availability_topic,
    payload_available: "online",
    payload_not_available: "offline",
    value_template: valueTpl,
    device,
    ...extra
  };

  if (unit) payload.unit_of_measurement = unit;
  if (device_class) payload.device_class = device_class;
  if (state_class) payload.state_class = state_class;

  publishedTopics.push(topic);
  return { topic, payload: JSON.stringify(payload), retain: true };
}

function selectCfg(objectId, name, options, valueTpl, commandTopic, extra = {}) {
  const uid = stableObjectId(objectId);
  const topic = `${HA_PREFIX}/select/${uid}/config`;
  const domain = entityDomainFromTopic(topic);

  const payload = {
    name,
    unique_id: uid,
    default_entity_id: `${domain}.${uid}`,
    state_topic,
    availability_topic,
    payload_available: "online",
    payload_not_available: "offline",
    value_template: valueTpl,
    command_topic: commandTopic,
    options,
    device,
    ...extra
  };

  publishedTopics.push(topic);
  return { topic, payload: JSON.stringify(payload), retain: true };
}

function numberCfg(objectId, name, unit, min, max, step, valueTpl, commandTopic, extra = {}) {
  const uid = stableObjectId(objectId);
  const topic = `${HA_PREFIX}/number/${uid}/config`;
  const domain = entityDomainFromTopic(topic);

  const payload = {
    name,
    unique_id: uid,
    default_entity_id: `${domain}.${uid}`,
    state_topic,
    availability_topic,
    payload_available: "online",
    payload_not_available: "offline",
    value_template: valueTpl,
    command_topic: commandTopic,
    unit_of_measurement: unit,
    min,
    max,
    step,
    mode: "box",
    device,
    ...extra
  };

  publishedTopics.push(topic);
  return { topic, payload: JSON.stringify(payload), retain: true };
}

function textCfg(objectId, name, commandTopic, extra = {}) {
  const uid = stableObjectId(objectId);
  const topic = `${HA_PREFIX}/text/${uid}/config`;
  const domain = entityDomainFromTopic(topic);

  const payload = {
    name,
    unique_id: uid,
