  };

  publishedTopics.push(topic);
  return { topic, payload: JSON.stringify(payload), retain: true };
}

function switchCfg(objectId, name, valueTpl, commandTopic, payloadOn = "ON", payloadOff = "OFF", extra = {}) {
  const uid = stableObjectId(objectId);
  const topic = `${HA_PREFIX}/switch/${uid}/config`;
  const domain = entityDomainFromTopic(topic);

  const payload = {
    name,
    unique_id: uid,
    default_entity_id: `${domain}.${uid}`,
    state_topic,
    availability_topic,
    payload_available: "online",
    payload_not_available: "offline",
    value_template: valueTpl,
    command_topic: commandTopic,
    payload_on: payloadOn,
    payload_off: payloadOff,
    state_on: "ON",
    state_off: "OFF",
    device,
    ...extra
  };

  publishedTopics.push(topic);
  return { topic, payload: JSON.stringify(payload), retain: true };
}

function clearPublishedTopics() {
  const topics = flow.get(topicsKey) || [];
  if (!Array.isArray(topics) || topics.length === 0) return [];
  return topics.map(t => ({ topic: t, payload: "", retain: true }));
}

// =======================
// Si cet onduleur n'est pas activé
// =======================
if (!enabled) {
  let msgs = [];
  if (changed) {
    msgs = clearPublishedTopics();
    flow.set(topicsKey, []);
    flow.set(lastSigKey, signature);
  }
  return [msgs];
}

// =======================
// 1) SENSORS
// =======================
const msgsSensors = [
  sensorCfg("ac_output_active_power", "AC Output Active Power", "W", "power", "measurement",
    jNum("value_json.ac_output_active_power", 0), { icon: "mdi:home-lightning-bolt-outline" }),
