  global.get(`inverter_${inv}.display_mode`) ||
  cfg.displayMode ||
  "modern"
).trim();

const outputPriorityTwoChoices = isTwoChoiceOutputPriorityEnabled(inv, cfg);

// signature de config pour ce discovery
const signature = JSON.stringify({
  enabled,
  transport: cfg.transport || "",
  serialPort: cfg.serialPort || "",
  gwHost: cfg.gwHost || "",
  gwPort: cfg.gwPort || "",
  batterySystemVoltage: sysV,
  displayMode,
  outputPriorityTwoChoices,
  premiumActive
