function switchCfg(objectId, name, valueTpl, commandTopic, payloadOn = "ON", payloadOff = "OFF", extra = {}) {
  const uid = stableObjectId(objectId);
  const topic = `${HA_PREFIX}/switch/${uid}/config`;
