function accentColor(kind = "neutral") {
    const map = {
        neutral: "var(--primary-color)",
        blue: "#3b82f6",
        green: "#22c55e",
        orange: "#f59e0b",
        purple: "#a855f7",
        red: "#ef4444",
        cyan: "#06b6d4",
        gold: "#d4a017"
    };
    return map[kind] || map.neutral;
}

