function miniGraph(title, entities, hours = 24, height = 260, kind = "neutral") {
    if (HAS_MINI_GRAPH) {
        return {
            type: "custom:mini-graph-card",
            name: title,
            hours_to_show: hours,
            points_per_hour: 2,
            hour24: true,
            animate: true,
            line_width: 3,
            font_size: 95,
            height,
            decimals: 2,
            show: {
                icon: false,
                name: true,
                state: true,
                legend: true,
                fill: true,
                labels: true,
                average: false,
                extrema: false
            },
            entities,
            ...cardStyle(kind)
        };
    }

    return {
        type: "history-graph",
        title,
        hours_to_show: hours,
        entities: entities.map(e => ({
            entity: typeof e === "string" ? e : e.entity,
            name: typeof e === "string" ? undefined : e.name
        })),
        ...cardStyle(kind)
    };
}

function statStrip(items) {
    return grid(
        items.length,
        items.map(i => tile(i.entity, i.name, i.icon, i.kind || "neutral"))
    );
}

