// =========================================================
// DONUT kWh
// =========================================================
function energyKwhDonut(title, series, kind = "gold") {
    if (HAS_APEXCHARTS) {
        return {
            type: "custom:apexcharts-card",
            chart_type: "donut",
            header: {
                show: true,
                title,
                show_states: true,
                colorize_states: true
            },
            all_series_config: {
                float_precision: 2,
                show: {
                    in_header: true,
                    legend_value: true
                }
            },
            series,
            apex_config: {
                chart: { height: 470 },
                colors: ["#f59e0b", "#38bdf8", "#ef4444", "#a855f7", "#22c55e"],
                legend: {
                    show: true,
                    position: "bottom",
                    fontSize: "12px",
                    formatter: evalLegend("kWh")
                },
                dataLabels: {
                    enabled: true,
                    formatter: evalFixed("")
                },
                tooltip: {
                    y: {
                        formatter: evalFixed("kWh")
                    }
                },
                plotOptions: {
                    pie: {
                        expandOnClick: false,
                        donut: {
                            size: "66%",
                            labels: {
                                show: true,
                                name: { show: true },
                                value: {
                                    show: true,
                                    formatter: evalFixed("kWh")
                                },
                                total: {
                                    show: true,
                                    label: "kWh",
                                    formatter: evalTotal("")
                                }
                            }
                        }
                    }
                }
            },
            ...cardStyle(kind)
        };
    }

    return entitiesCard(title, series.map(s => s.entity), kind);
}

