// -------------------------
// Build dashboard
// -------------------------
const invs = enabledInverters();

if (!invs.length) {
    node.warn(t.no_inverter);
    return null;
}

const overviewViewCards = [];
const energyViewCards = [];
const parameterViewCards = [];
const healthDiagViewCards = [];

const warning = missingCardsWarning();
if (warning) {
    overviewViewCards.push(warning);
}

for (const inv of invs) {
    overviewViewCards.push(overviewCards(inv));
    energyViewCards.push(energyCards(inv));
    parameterViewCards.push(parameterCards(inv));
    healthDiagViewCards.push(healthDiagCards(inv));
}

const dashboard = {
    dashboard_meta: {
        url_path: "smart-voltronic",
        title: "Smart Voltronic",
        icon: "mdi:solar-power",
        show_in_sidebar: true
    },
    config: {
        views: [
            {
                title: t.view_overview,
                path: "overview",
                icon: "mdi:home-analytics",
                cards: overviewViewCards
            },
            {
                title: t.view_energy,
                path: "energy",
                icon: "mdi:chart-box",
                cards: energyViewCards
            },
            {
                title: t.view_parameters,
                path: "parameters",
                icon: "mdi:tune",
                cards: parameterViewCards
            },
            {
                title: t.view_health_diag,
                path: "health-diag",
                icon: "mdi:stethoscope",
                cards: healthDiagViewCards
            }
        ]
    }
};

if (customCardsInstalled) {
    node.log(`Dashboard premium généré [lang=${lang}]`);
} else {
    node.warn(`Dashboard premium généré en mode dégradé [lang=${lang}]`);
}

msg.payload = JSON.stringify(dashboard, null, 2);
msg.filename = "/config/dashboards/smart_voltronic.json";
return msg;

const premiumActive = global.get("premium.active") === true;

if (premiumActive) {
    return [msg, null];
} else {
    return [null, msg];
}

const inputEnv = msg.payload.toString().trim();

let configPath;
let statusColor;
let bip;

switch(inputEnv) {
    case 'HAOS':
        configPath = '/data/options.json';
        msg.environment = 'Home Assistant OS';
        bip = 1;
        statusColor = 'green';
        break;
    case 'Docker':
        configPath = '/data/options.json';
        msg.environment = 'Docker (autre)';
        bip = 2;
        statusColor = 'blue';
        break;
    case 'Linux':
        configPath = '/data/options.json';
        msg.environment = 'Linux barebone';
        bip = 3;
        statusColor = 'yellow';
        break;
    case 'Windows':
        configPath = 'C:\\data\\options.json';
        msg.environment = 'Windows';
        bip = 4;
        statusColor = 'purple';
        break;
    default:
        configPath = './data/options.json';
        msg.environment = 'Inconnu';
        bip = 5;
        statusColor = 'red';
}

msg.filename = configPath;
msg.payload = {"bip": String(bip)};
msg.headers = {
    "Content-Type": "application/json"
};
node.status({fill:statusColor, shape:"dot", text: msg.environment});
return msg;
